{
  "name": "TesourariaPro",
  "description": "Sistema completo para gestão financeira de associações, incluindo fluxo de caixa, contas a pagar/receber, conciliação bancária e análise financeira com IA."
}

export type TransactionType = 'income' | 'expense';
export type TransactionStatus = 'pending' | 'completed' | 'cancelled';
export type PaymentMethod = 'bank_transfer' | 'credit_card' | 'cash' | 'check' | 'pix';

export interface Category {
  id: string;
  name: string;
  type: TransactionType;
  budgetLimit?: number;
}

export interface Transaction {
  id: string;
  date: string;
  description: string;
  amount: number;
  type: TransactionType;
  category: string;
  status: TransactionStatus;
  paymentMethod: PaymentMethod;
  notes?: string;
  reconciled: boolean;
}

export interface FinancialSummary {
  totalIncome: number;
  totalExpense: number;
  balance: number;
  pendingIncome: number;
  pendingExpense: number;
}

export interface AIAnalysisResult {
  summary: string;
  risks: string[];
  recommendations: string[];
  lastUpdated: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { Transaction, AIAnalysisResult } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const analyzeFinancialHealth = async (transactions: Transaction[]): Promise<AIAnalysisResult> => {
  if (!apiKey) {
    throw new Error("API Key não configurada.");
  }

  // Filter last 60 days to keep context manageable
  const recentTransactions = transactions.slice(0, 50).map(t => ({
    date: t.date,
    type: t.type,
    amount: t.amount,
    category: t.category,
    status: t.status
  }));

  const prompt = `
    Atue como um tesoureiro sênior especialista em gestão de associações sem fins lucrativos.
    Analise os seguintes dados de transações financeiras recentes.

    Dados das Transações:
    ${JSON.stringify(recentTransactions)}

    Por favor, forneça uma análise estruturada contendo:
    1. Um resumo executivo da saúde financeira.
    2. Identificação de riscos financeiros (ex: liquidez, dependência de uma fonte de receita, gastos excessivos).
    3. Recomendações estratégicas para melhoria orçamentária e sustentabilidade.

    Retorne a resposta estritamente em formato JSON seguindo este esquema.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING },
            risks: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
            recommendations: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
          },
          required: ["summary", "risks", "recommendations"]
        }
      }
    });

    const result = JSON.parse(response.text || "{}");

    return {
      summary: result.summary || "Não foi possível gerar o resumo.",
      risks: result.risks || [],
      recommendations: result.recommendations || [],
      lastUpdated: new Date().toISOString()
    };

  } catch (error) {
    console.error("Erro ao analisar finanças com Gemini:", error);
    throw error;
  }
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { Transaction, Category, FinancialSummary, AIAnalysisResult } from '../types';

interface FinanceContextType {
  transactions: Transaction[];
  categories: Category[];
  addTransaction: (t: Omit<Transaction, 'id'>) => void;
  updateTransaction: (t: Transaction) => void;
  deleteTransaction: (id: string) => void;
  getSummary: () => FinancialSummary;
  aiAnalysis: AIAnalysisResult | null;
  setAiAnalysis: (analysis: AIAnalysisResult) => void;
}

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

// Mock Data
const INITIAL_CATEGORIES: Category[] = [
  { id: '1', name: 'Mensalidades de Associados', type: 'income', budgetLimit: 0 },
  { id: '2', name: 'Doações', type: 'income', budgetLimit: 0 },
  { id: '3', name: 'Eventos', type: 'income', budgetLimit: 0 },
  { id: '4', name: 'Salários e Encargos', type: 'expense', budgetLimit: 15000 },
  { id: '5', name: 'Aluguel e Condomínio', type: 'expense', budgetLimit: 3000 },
  { id: '6', name: 'Manutenção', type: 'expense', budgetLimit: 1000 },
  { id: '7', name: 'Material de Escritório', type: 'expense', budgetLimit: 500 },
  { id: '8', name: 'Serviços de Terceiros (Contabilidade)', type: 'expense', budgetLimit: 1200 },
];

const INITIAL_TRANSACTIONS: Transaction[] = [
  { id: '1', date: '2023-10-01', description: 'Mensalidades Outubro', amount: 8500, type: 'income', category: 'Mensalidades de Associados', status: 'completed', paymentMethod: 'pix', reconciled: true },
  { id: '2', date: '2023-10-05', description: 'Pagamento Aluguel Sede', amount: 2800, type: 'expense', category: 'Aluguel e Condomínio', status: 'completed', paymentMethod: 'bank_transfer', reconciled: true },
  { id: '3', date: '2023-10-05', description: 'Serviço de Contabilidade', amount: 1200, type: 'expense', category: 'Serviços de Terceiros (Contabilidade)', status: 'pending', paymentMethod: 'bank_transfer', reconciled: false },
  { id: '4', date: '2023-10-10', description: 'Compra Papel A4 e Toner', amount: 350, type: 'expense', category: 'Material de Escritório', status: 'completed', paymentMethod: 'credit_card', reconciled: true },
  { id: '5', date: '2023-10-12', description: 'Doação Anônima', amount: 5000, type: 'income', category: 'Doações', status: 'completed', paymentMethod: 'bank_transfer', reconciled: true },
  { id: '6', date: '2023-10-15', description: 'Adiantamento Salarial', amount: 4000, type: 'expense', category: 'Salários e Encargos', status: 'completed', paymentMethod: 'bank_transfer', reconciled: true },
  { id: '7', date: '2023-10-20', description: 'Manutenção Ar Condicionado', amount: 450, type: 'expense', category: 'Manutenção', status: 'pending', paymentMethod: 'check', reconciled: false },
  { id: '8', date: '2023-10-25', description: 'Venda de Ingressos Jantar Beneficente', amount: 3200, type: 'income', category: 'Eventos', status: 'pending', paymentMethod: 'pix', reconciled: false },
];

export const FinanceProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [transactions, setTransactions] = useState<Transaction[]>(INITIAL_TRANSACTIONS);
  const [categories, setCategories] = useState<Category[]>(INITIAL_CATEGORIES);
  const [aiAnalysis, setAiAnalysis] = useState<AIAnalysisResult | null>(null);

  const addTransaction = (t: Omit<Transaction, 'id'>) => {
    const newTransaction = { ...t, id: Math.random().toString(36).substr(2, 9) };
    setTransactions(prev => [newTransaction, ...prev]);
  };

  const updateTransaction = (updated: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updated.id ? updated : t));
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const getSummary = (): FinancialSummary => {
    return transactions.reduce((acc, t) => {
      const isIncome = t.type === 'income';
      const isCompleted = t.status === 'completed';

      if (isIncome) {
        if (isCompleted) acc.totalIncome += t.amount;
        else acc.pendingIncome += t.amount;
      } else {
        if (isCompleted) acc.totalExpense += t.amount;
        else acc.pendingExpense += t.amount;
      }

      if (isCompleted) {
        acc.balance += isIncome ? t.amount : -t.amount;
      }

      return acc;
    }, {
      totalIncome: 0,
      totalExpense: 0,
      balance: 0,
      pendingIncome: 0,
      pendingExpense: 0
    });
  };

  return (
    <FinanceContext.Provider value={{
      transactions,
      categories,
      addTransaction,
      updateTransaction,
      deleteTransaction,
      getSummary,
      aiAnalysis,
      setAiAnalysis
    }}>
      {children}
    </FinanceContext.Provider>
  );
};

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error('useFinance must be used within a FinanceProvider');
  return context;
};

