                   <td className="px-6 py-4">
                    <button 
                        onClick={() => handleReconcile(t)}
                        title={t.reconciled ? "Marcar como não conciliado" : "Conciliar (Confirmar no Banco)"}
                        className={`transition-colors ${t.reconciled ? 'text-blue-600' : 'text-slate-300 hover:text-blue-500'}`}
                    >
                        <FileSpreadsheet size={20} />
                    </button>
                  </td>
                  <td className="px-6 py-4">
                    <button onClick={() => {/* Delete logic */}} className="text-slate-400 hover:text-rose-500 transition-colors">
                        <XCircle size={18} />
                    </button>
                  </td>
                </tr>
              ))}
              {filteredTransactions.length === 0 && (
                <tr>
                    <td colSpan={7} className="px-6 py-12 text-center text-slate-500">
                        Nenhuma transação encontrada para os filtros selecionados.
                    </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default TransactionManager;

import React, { useState } from 'react';
import { useFinance } from '../context/FinanceContext';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend, BarChart, Bar, XAxis, YAxis, CartesianGrid } from 'recharts';
import { analyzeFinancialHealth } from '../services/geminiService';
import { Bot, RefreshCw, AlertTriangle, Lightbulb, TrendingUp } from 'lucide-react';

const COLORS = ['#10b981', '#3b82f6', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899'];

const Reports: React.FC = () => {
  const { transactions, categories, aiAnalysis, setAiAnalysis } = useFinance();
  const [loadingAi, setLoadingAi] = useState(false);
  const [errorAi, setErrorAi] = useState<string | null>(null);

  // Calculate data for Pie Chart (Expenses by Category)
  const expensesByCategory = categories
    .filter(c => c.type === 'expense')
    .map(c => {
      const total = transactions
        .filter(t => t.category === c.name && t.type === 'expense')
        .reduce((sum, t) => sum + t.amount, 0);
      return { name: c.name, value: total };
    })
    .filter(item => item.value > 0);

  // Generate Analysis
  const handleGenerateAnalysis = async () => {
    setLoadingAi(true);
    setErrorAi(null);
    try {
      const result = await analyzeFinancialHealth(transactions);
      setAiAnalysis(result);
    } catch (e) {
      setErrorAi("Erro ao conectar com o Assistente Inteligente. Verifique a chave de API.");
    } finally {
      setLoadingAi(false);
    }
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

