            </div>
        </div>
      </div>

      {/* Additional Reporting Placeholder */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
         <h3 className="text-lg font-bold text-slate-800 mb-4">Evolução Orçamentária</h3>
