import React, { useState } from 'react';
import { useFinance } from '../context/FinanceContext';
import { Transaction, TransactionType, PaymentMethod } from '../types';
import { Plus, Search, CheckCircle, Clock, FileSpreadsheet, ChevronDown, ChevronUp, CreditCard, StickyNote, Trash2 } from 'lucide-react';

const TransactionManager: React.FC = () => {
  const { transactions, addTransaction, updateTransaction, deleteTransaction, categories } = useFinance();
  const [showForm, setShowForm] = useState(false);
  const [filterType, setFilterType] = useState<'all' | TransactionType>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [expandedId, setExpandedId] = useState<string | null>(null);

  // Form State
  const [formData, setFormData] = useState({
    description: '',
    amount: '',
    date: new Date().toISOString().split('T')[0],
    type: 'expense' as TransactionType,
    category: '',
    status: 'completed' as const,
    paymentMethod: 'bank_transfer' as PaymentMethod,
    notes: '',
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.description || !formData.amount || !formData.category) return;

    addTransaction({
      description: formData.description,
      amount: parseFloat(formData.amount),
      date: formData.date,
      type: formData.type,
      category: formData.category,
      status: formData.status,
      paymentMethod: formData.paymentMethod,
      notes: formData.notes,
      reconciled: false
    });

    setShowForm(false);
    setFormData({
      description: '',
      amount: '',
      date: new Date().toISOString().split('T')[0],
      type: 'expense',
      category: '',
      status: 'completed',
      paymentMethod: 'bank_transfer',
      notes: '',
    });
  };

  const handleReconcile = (e: React.MouseEvent, t: Transaction) => {
    e.stopPropagation();
    updateTransaction({ ...t, reconciled: !t.reconciled });
  };

  const handleDelete = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      if(window.confirm('Tem certeza que deseja excluir esta transação?')) {
          deleteTransaction(id);
      }
  }

  const toggleExpand = (id: string) => {
    setExpandedId(prev => prev === id ? null : id);
  };

  const filteredTransactions = transactions.filter(t => {
    const matchesType = filterType === 'all' || t.type === filterType;
    const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          t.category.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesType && matchesSearch;
  });

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const getPaymentMethodLabel = (method: PaymentMethod) => {
      const labels: Record<PaymentMethod, string> = {
          bank_transfer: 'Transferência Bancária',
          credit_card: 'Cartão de Crédito',
          cash: 'Dinheiro',
          check: 'Cheque',
          pix: 'PIX'
      };
      return labels[method] || method;
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
           <h2 className="text-2xl font-bold text-slate-800">Fluxo de Caixa</h2>
           <p className="text-slate-500">Gestão de Entradas e Saídas</p>
        </div>
        <button 
          onClick={() => setShowForm(!showForm)}
          className="bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors"
        >
          <Plus size={20} />
          Nova Transação
        </button>
      </div>

      {showForm && (
        <div className="bg-white p-6 rounded-xl shadow-lg border border-slate-200 animate-in fade-in slide-in-from-top-4">
          <h3 className="text-lg font-bold text-slate-800 mb-4">Adicionar Transação</h3>
          <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            <div className="col-span-2">
              <label className="block text-sm font-medium text-slate-700 mb-1">Descrição</label>
              <input 
                type="text" 
                required
                className="w-full border border-slate-300 rounded-lg p-2 focus:ring-2 focus:ring-emerald-500 outline-none"
                value={formData.description}
                onChange={e => setFormData({...formData, description: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Valor (R$)</label>
              <input 
                type="number" 
                step="0.01"
                required
                className="w-full border border-slate-300 rounded-lg p-2 focus:ring-2 focus:ring-emerald-500 outline-none"
                value={formData.amount}
                onChange={e => setFormData({...formData, amount: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Data</label>
              <input 
                type="date" 
                required
                className="w-full border border-slate-300 rounded-lg p-2 focus:ring-2 focus:ring-emerald-500 outline-none"
                value={formData.date}
                onChange={e => setFormData({...formData, date: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Tipo</label>
              <select 
                className="w-full border border-slate-300 rounded-lg p-2 focus:ring-2 focus:ring-emerald-500 outline-none"
                value={formData.type}
                onChange={e => setFormData({...formData, type: e.target.value as TransactionType})}
              >
                <option value="income">Receita</option>
                <option value="expense">Despesa</option>
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Categoria</label>
              <select 
                className="w-full border border-slate-300 rounded-lg p-2 focus:ring-2 focus:ring-emerald-500 outline-none"
                value={formData.category}
                onChange={e => setFormData({...formData, category: e.target.value})}
                required
              >
                <option value="">Selecione...</option>
                {categories.filter(c => c.type === formData.type).map(c => (
                  <option key={c.id} value={c.name}>{c.name}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Status</label>
              <select 
                className="w-full border border-slate-300 rounded-lg p-2 focus:ring-2 focus:ring-emerald-500 outline-none"
                value={formData.status}
                onChange={e => setFormData({...formData, status: e.target.value as any})}
              >
                <option value="completed">Concluído</option>
                <option value="pending">Pendente</option>
              </select>
            </div>
             <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Meio de Pagamento</label>
              <select 
                className="w-full border border-slate-300 rounded-lg p-2 focus:ring-2 focus:ring-emerald-500 outline-none"
                value={formData.paymentMethod}
                onChange={e => setFormData({...formData, paymentMethod: e.target.value as any})}
              >
                <option value="bank_transfer">Transf. Bancária</option>
                <option value="pix">PIX</option>
                <option value="credit_card">Cartão de Crédito</option>
                <option value="check">Cheque</option>
                <option value="cash">Dinheiro</option>
              </select>
            </div>
             <div className="col-span-2 lg:col-span-4">
              <label className="block text-sm font-medium text-slate-700 mb-1">Notas (Opcional)</label>
              <input 
                type="text" 
                className="w-full border border-slate-300 rounded-lg p-2 focus:ring-2 focus:ring-emerald-500 outline-none"
                value={formData.notes}
                onChange={e => setFormData({...formData, notes: e.target.value})}
                placeholder="Detalhes adicionais..."
              />
            </div>
            <div className="md:col-span-2 lg:col-span-4 flex justify-end gap-3 mt-4">
              <button 
                type="button" 
                onClick={() => setShowForm(false)}
                className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg"
              >
                Cancelar
              </button>
              <button 
                type="submit" 
                className="px-4 py-2 bg-emerald-600 hover:bg-emerald-700 text-white rounded-lg"
              >
                Salvar Lançamento
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Filters */}
      <div className="flex flex-col md:flex-row gap-4 bg-white p-4 rounded-xl shadow-sm border border-slate-100">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={18} />
          <input 
            type="text" 
            placeholder="Buscar por descrição ou categoria..." 
            className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-emerald-500"
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="flex gap-2">
            <button 
                onClick={() => setFilterType('all')}
                className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${filterType === 'all' ? 'bg-slate-800 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}
            >
                Todos
            </button>
            <button 
                onClick={() => setFilterType('income')}
                className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${filterType === 'income' ? 'bg-emerald-600 text-white' : 'bg-emerald-50 text-emerald-700 hover:bg-emerald-100'}`}
            >
                Receitas
            </button>
            <button 
                onClick={() => setFilterType('expense')}
                className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${filterType === 'expense' ? 'bg-rose-600 text-white' : 'bg-rose-50 text-rose-700 hover:bg-rose-100'}`}
            >
                Despesas
            </button>
        </div>
      </div>

      {/* Table */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4 w-12"></th>
                <th className="px-6 py-4 font-semibold text-slate-700">Data</th>
                <th className="px-6 py-4 font-semibold text-slate-700">Descrição</th>
                <th className="px-6 py-4 font-semibold text-slate-700">Categoria</th>
                <th className="px-6 py-4 font-semibold text-slate-700">Valor</th>
                <th className="px-6 py-4 font-semibold text-slate-700">Status</th>
                <th className="px-6 py-4 font-semibold text-slate-700">Conciliado</th>
                <th className="px-6 py-4 font-semibold text-slate-700">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredTransactions.map(t => (
                <React.Fragment key={t.id}>
                    <tr 
                        onClick={() => toggleExpand(t.id)}
                        className={`hover:bg-slate-50 transition-colors cursor-pointer ${expandedId === t.id ? 'bg-slate-50' : ''}`}
                    >
                    <td className="px-6 py-4 text-slate-400">
                        {expandedId === t.id ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
                    </td>
                    <td className="px-6 py-4 text-slate-600 whitespace-nowrap">{t.date}</td>
                    <td className="px-6 py-4 font-medium text-slate-800">{t.description}</td>
                    <td className="px-6 py-4">
                        <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-slate-100 text-slate-800">
                        {t.category}
                        </span>
                    </td>
                    <td className={`px-6 py-4 font-bold ${t.type === 'income' ? 'text-emerald-600' : 'text-rose-600'}`}>
                        {t.type === 'income' ? '+' : '-'}{formatCurrency(t.amount)}
                    </td>
                    <td className="px-6 py-4">
                        {t.status === 'completed' ? (
                            <span className="inline-flex items-center gap-1 text-emerald-700 bg-emerald-50 px-2 py-1 rounded text-xs">
                                <CheckCircle size={12} /> Pago
                            </span>
                        ) : (
                            <span className="inline-flex items-center gap-1 text-amber-700 bg-amber-50 px-2 py-1 rounded text-xs">
                                <Clock size={12} /> Pendente
                            </span>
                        )}
                    </td>
                    <td className="px-6 py-4">
                        <button 
                            onClick={(e) => handleReconcile(e, t)}
                            title={t.reconciled ? "Marcar como não conciliado" : "Conciliar (Confirmar no Banco)"}
                            className={`transition-colors ${t.reconciled ? 'text-blue-600' : 'text-slate-300 hover:text-blue-500'}`}
                        >
                            <FileSpreadsheet size={20} />
                        </button>
                    </td>
                    <td className="px-6 py-4">
                        <button onClick={(e) => handleDelete(e, t.id)} className="text-slate-400 hover:text-rose-500 transition-colors">
                            <Trash2 size={18} />
                        </button>
                    </td>
                    </tr>
                    {expandedId === t.id && (
                        <tr className="bg-slate-50 border-b border-slate-100">
                            <td colSpan={8} className="px-6 py-4">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 p-2">
                                    <div className="space-y-4">
                                        <div>
                                            <span className="flex items-center gap-2 text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1">
                                                <CreditCard size={14} /> Método de Pagamento
                                            </span>
                                            <p className="text-sm font-medium text-slate-700 pl-6">
                                                {getPaymentMethodLabel(t.paymentMethod)}
                                            </p>
                                        </div>
                                        <div>
                                            <span className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1 block pl-6">ID da Transação</span>
                                            <p className="text-xs font-mono text-slate-400 pl-6">{t.id}</p>
                                        </div>
                                    </div>
                                    <div>
                                        <span className="flex items-center gap-2 text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1">
                                            <StickyNote size={14} /> Notas & Observações
                                        </span>
                                        <div className="bg-white p-3 rounded border border-slate-200 text-sm text-slate-600 ml-6">
                                            {t.notes || <span className="text-slate-400 italic">Nenhuma observação registrada.</span>}
                                        </div>
                                    </div>
                                </div>
                            </td>
                        </tr>
                    )}
                </React.Fragment>
              ))}
              {filteredTransactions.length === 0 && (
                <tr>
                    <td colSpan={8} className="px-6 py-12 text-center text-slate-500">
                        Nenhuma transação encontrada para os filtros selecionados.
                    </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

