import React, { useState } from 'react';
import { useFinance } from '../context/FinanceContext';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';
import { Printer, Calendar } from 'lucide-react';

const COLORS = ['#10b981', '#3b82f6', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899'];

const Reports: React.FC = () => {
  const { transactions, categories } = useFinance();

  // State for Report Date Range
  const [dateRange, setDateRange] = useState({
    start: new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0],
    end: new Date().toISOString().split('T')[0]
  });

  // Calculate data for Pie Chart (Expenses by Category)
  const expensesByCategory = categories
    .filter(c => c.type === 'expense')
    .map(c => {
      const total = transactions
        .filter(t => t.category === c.name && t.type === 'expense')
        .reduce((sum, t) => sum + t.amount, 0);
      return { name: c.name, value: total };
    })
    .filter(item => item.value > 0);

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const formatDate = (dateStr: string) => {
    if (!dateStr) return '';
    const [year, month, day] = dateStr.split('-');
    return `${day}/${month}/${year}`;
  };

  // Report Generation Logic
  const reportTransactions = transactions
    .filter(t => t.date >= dateRange.start && t.date <= dateRange.end)
    .sort((a, b) => a.date.localeCompare(b.date));

  const reportSummary = reportTransactions.reduce((acc, t) => {
    if (t.type === 'income') acc.income += t.amount;
    else acc.expense += t.amount;
    return acc;
  }, { income: 0, expense: 0 });

  const handlePrint = () => {
    window.print();
  };

  return (
    <div className="space-y-8">
      {/* Print CSS Styles */}
      <style>{`
        @media print {
          body * {
            visibility: hidden;
          }
          #printable-report, #printable-report * {
            visibility: visible;
          }
          #printable-report {
            position: absolute;
            left: 0;
            top: 0;
            width: 100%;
            background: white;
            padding: 20px;
            z-index: 9999;
          }
          /* Hide the main app UI elements */
          nav, aside, header, .no-print {
            display: none !important;
          }
        }
      `}</style>

      <div className="no-print">
         <h2 className="text-2xl font-bold text-slate-800">Relatórios Gerenciais</h2>
         <p className="text-slate-500">Visualização de despesas e emissão de demonstrativos</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 no-print">
        {/* Expense Distribution */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
            <h3 className="text-lg font-bold text-slate-800 mb-4">Distribuição de Despesas</h3>
            <div className="h-72">
                <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                        <Pie
                            data={expensesByCategory}
                            cx="50%"
                            cy="50%"
                            innerRadius={60}
                            outerRadius={80}
                            fill="#8884d8"
                            paddingAngle={5}
                            dataKey="value"
                        >
                            {expensesByCategory.map((entry, index) => (
                                <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                            ))}
                        </Pie>
                        <Tooltip formatter={(value: number) => formatCurrency(value)} />
                        <Legend />
                    </PieChart>
                </ResponsiveContainer>
            </div>
        </div>

        {/* Report Generation Section */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex flex-col justify-between">
           <div>
               <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2 mb-2">
                   <Printer size={20} className="text-slate-500"/> 
                   Emissão de Relatórios
               </h3>
               <p className="text-sm text-slate-500 mb-6">Selecione o período desejado para gerar e imprimir o demonstrativo financeiro detalhado.</p>

               <div className="space-y-4">
                  <div>
                      <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-2">
                          <Calendar size={14} /> Data Inicial
                      </label>
                      <input 
                          type="date" 
                          value={dateRange.start}
                          onChange={(e) => setDateRange({...dateRange, start: e.target.value})}
                          className="w-full border border-slate-300 rounded-lg p-2 focus:ring-2 focus:ring-emerald-500 outline-none"
                      />
                  </div>
                  <div>
                      <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-2">
                          <Calendar size={14} /> Data Final
                      </label>
                      <input 
                          type="date" 
                          value={dateRange.end}
                          onChange={(e) => setDateRange({...dateRange, end: e.target.value})}
                          className="w-full border border-slate-300 rounded-lg p-2 focus:ring-2 focus:ring-emerald-500 outline-none"
                      />
                  </div>
               </div>
           </div>

           <div className="mt-8 pt-6 border-t border-slate-100">
              <button 
                  onClick={handlePrint}
                  className="w-full bg-slate-800 hover:bg-slate-700 text-white px-4 py-3 rounded-lg flex items-center justify-center gap-2 transition-colors font-medium"
              >
                  <Printer size={18} />
                  Imprimir Relatório
              </button>
           </div>
        </div>
      </div>

      {/* Hidden Printable Area */}
      <div id="printable-report" className="hidden">
        <div className="text-center mb-8 border-b-2 border-slate-800 pb-4">
            <h1 className="text-3xl font-bold text-slate-900 uppercase tracking-wide">TesourariaPro</h1>
            <h2 className="text-xl text-slate-700 mt-2">Demonstrativo Financeiro</h2>
            <p className="text-slate-500 mt-1">Período: {formatDate(dateRange.start)} até {formatDate(dateRange.end)}</p>
        </div>

        <div className="mb-8">
            <h3 className="text-lg font-bold text-slate-800 mb-4 border-l-4 border-emerald-500 pl-3">Resumo do Período</h3>
            <div className="grid grid-cols-3 gap-4">
                <div className="p-4 bg-gray-50 border border-gray-200 rounded">
                    <p className="text-sm text-gray-500 uppercase">Total Receitas</p>
                    <p className="text-xl font-bold text-emerald-600">{formatCurrency(reportSummary.income)}</p>
                </div>
                <div className="p-4 bg-gray-50 border border-gray-200 rounded">
                    <p className="text-sm text-gray-500 uppercase">Total Despesas</p>
                    <p className="text-xl font-bold text-rose-600">{formatCurrency(reportSummary.expense)}</p>
                </div>
                <div className="p-4 bg-gray-50 border border-gray-200 rounded">
                    <p className="text-sm text-gray-500 uppercase">Resultado</p>
                    <p className={`text-xl font-bold ${reportSummary.income - reportSummary.expense >= 0 ? 'text-blue-600' : 'text-red-600'}`}>
                        {formatCurrency(reportSummary.income - reportSummary.expense)}
                    </p>
                </div>
            </div>
        </div>

        <div className="mb-12">
            <h3 className="text-lg font-bold text-slate-800 mb-4 border-l-4 border-slate-500 pl-3">Detalhamento de Transações</h3>
            <table className="w-full text-sm text-left border-collapse">
                <thead>
                    <tr className="bg-gray-100 border-b-2 border-gray-300">
                        <th className="px-4 py-2">Data</th>
                        <th className="px-4 py-2">Descrição</th>
                        <th className="px-4 py-2">Categoria</th>
                        <th className="px-4 py-2">Método</th>
                        <th className="px-4 py-2 text-right">Valor</th>
                    </tr>
                </thead>
                <tbody>
                    {reportTransactions.map((t, idx) => (
                        <tr key={t.id} className={`border-b border-gray-200 ${idx % 2 === 0 ? 'bg-white' : 'bg-gray-50'}`}>
                            <td className="px-4 py-2">{formatDate(t.date)}</td>
                            <td className="px-4 py-2">{t.description}</td>
                            <td className="px-4 py-2">{t.category}</td>
                            <td className="px-4 py-2 capitalize">{t.paymentMethod.replace('_', ' ')}</td>
                            <td className={`px-4 py-2 text-right font-bold whitespace-nowrap ${t.type === 'income' ? 'text-green-700' : 'text-red-700'}`}>
