                </tbody>
            </table>
        </div>

        <div className="mt-20 grid grid-cols-2 gap-20">
            <div className="text-center border-t border-slate-400 pt-4">
                <p className="font-bold text-slate-800">Tesoureiro(a)</p>
                <p className="text-xs text-slate-500">Assinatura</p>
            </div>
            <div className="text-center border-t border-slate-400 pt-4">
                <p className="font-bold text-slate-800">Presidente</p>
                <p className="text-xs text-slate-500">Assinatura</p>
            </div>
        </div>

        <div className="mt-8 text-center text-xs text-slate-400">
            Relatório gerado automaticamente pelo sistema TesourariaPro em {new Date().toLocaleString()}
        </div>
      </div>
    </div>
  );
};

