                <React.Fragment key={t.id}>
                    <tr 
                        onClick={() => toggleExpand(t.id)}
                        className={`hover:bg-slate-50 transition-colors cursor-pointer ${expandedId === t.id ? 'bg-slate-50' : ''}`}
                    >
                    <td className="px-6 py-4 text-slate-400">
                        {expandedId === t.id ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
                    </td>
                    <td className="px-6 py-4 text-slate-600 whitespace-nowrap">{t.date}</td>
                    <td className="px-6 py-4 font-medium text-slate-800 flex items-center gap-2">
                        {t.attachment && <Paperclip size={14} className="text-slate-400" />}
                        {t.description}
                    </td>
                    <td className="px-6 py-4 text-slate-600">{getAccountName(t.accountId)}</td>
                    <td className="px-6 py-4">
                        <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-slate-100 text-slate-800">
                        {t.category}
                        </span>
                    </td>
                    <td className={`px-6 py-4 font-bold ${t.type === 'income' ? 'text-emerald-600' : 'text-rose-600'}`}>
                        {t.type === 'income' ? '+' : '-'}{formatCurrency(t.amount)}
                    </td>
                    <td className="px-6 py-4">
                        {t.status === 'completed' ? (
                            <span className="inline-flex items-center gap-1 text-emerald-700 bg-emerald-50 px-2 py-1 rounded text-xs">
                                <CheckCircle size={12} /> Pago
                            </span>
                        ) : (
                            <span className="inline-flex items-center gap-1 text-amber-700 bg-amber-50 px-2 py-1 rounded text-xs">
                                <Clock size={12} /> Pendente
                            </span>
                        )}
                    </td>
                    <td className="px-6 py-4 text-right">
                        <div className="flex justify-end gap-2">
                            <button 
                                onClick={(e) => handleReconcile(e, t)}
                                title={t.reconciled ? "Marcar como não conciliado" : "Conciliar (Confirmar no Banco)"}
                                className={`transition-colors p-1 ${t.reconciled ? 'text-blue-600' : 'text-slate-300 hover:text-blue-500'}`}
                            >
                                <FileSpreadsheet size={20} />
                            </button>
                            <button 
                                onClick={(e) => handleEdit(e, t)} 
                                className="text-slate-400 hover:text-emerald-600 p-1"
                                title="Editar"
                            >
                                <Pencil size={18} />
                            </button>
                            <button 
                                onClick={(e) => handleDelete(e, t.id)} 
                                className="text-slate-400 hover:text-rose-500 p-1"
                                title="Excluir"
                            >
                                <Trash2 size={18} />
                            </button>
                        </div>
                    </td>
                    </tr>
                    {expandedId === t.id && (
                        <tr className="bg-slate-50 border-b border-slate-100">
                            <td colSpan={8} className="px-6 py-4">
                                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 p-2">
                                    <div className="space-y-4">
                                        <div>
                                            <span className="flex items-center gap-2 text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1">
                                                <CreditCard size={14} /> Método de Pagamento
                                            </span>
                                            <p className="text-sm font-medium text-slate-700 pl-6">
                                                {getPaymentMethodLabel(t.paymentMethod)}
                                            </p>
                                        </div>
                                        <div>
                                            <span className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1 block pl-6">ID da Transação</span>
                                            <p className="text-xs font-mono text-slate-400 pl-6">{t.id}</p>
                                        </div>
                                    </div>
                                    <div>
                                        <span className="flex items-center gap-2 text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1">
                                            <StickyNote size={14} /> Notas & Observações
                                        </span>
                                        <div className="bg-white p-3 rounded border border-slate-200 text-sm text-slate-600 ml-6">
                                            {t.notes || <span className="text-slate-400 italic">Nenhuma observação registrada.</span>}
                                        </div>
                                    </div>
                                    <div>
                                         <span className="flex items-center gap-2 text-xs font-semibold text-slate-500 uppercase tracking-wider mb-1">
                                            <Paperclip size={14} /> Anexos
                                        </span>
                                        <div className="bg-white p-3 rounded border border-slate-200 text-sm text-slate-600 ml-6 flex items-center justify-between">
                                            {t.attachment ? (
                                                <>
                                                    <span className="truncate max-w-[150px]">{t.attachment}</span>
                                                    <span className="text-xs bg-emerald-100 text-emerald-700 px-2 py-0.5 rounded">Arquivo</span>
                                                </>
                                            ) : (
                                                <span className="text-slate-400 italic">Nenhum documento anexado.</span>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            </td>
                        </tr>
                    )}
                </React.Fragment>
              ))}
              {filteredTransactions.length === 0 && (
                <tr>
                    <td colSpan={8} className="px-6 py-12 text-center text-slate-500">
                        Nenhuma transação encontrada para os filtros selecionados.
                    </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

