    );
  }

  if (!session) {
    return <Login onLogin={() => {}} />; // Session update is handled by listener
  }

  return (
    <FinanceProvider>
        <HashRouter>
            <Routes>
                <Route path="/" element={<Layout />}>
                    <Route index element={<Dashboard />} />
                    <Route path="accounts" element={<AccountManager />} />
