import React, { createContext, useContext, useState, ReactNode, useEffect } from 'react';
import { Transaction, Category, FinancialSummary, Account } from '../types';
import { supabase } from '../services/supabaseClient';

interface FinanceContextType {
  transactions: Transaction[];
  categories: Category[];
  accounts: Account[];
  associationName: string;
  loading: boolean;
  updateAssociationName: (name: string) => Promise<void>;
  addTransaction: (t: Omit<Transaction, 'id'>) => Promise<void>;
  updateTransaction: (t: Transaction) => Promise<void>;
  deleteTransaction: (id: string) => Promise<void>;
  addAccount: (a: Omit<Account, 'id'>) => Promise<void>;
  updateAccount: (a: Account) => Promise<void>;
  deleteAccount: (id: string) => Promise<void>;
  addCategory: (c: Omit<Category, 'id'>) => Promise<void>;
  updateCategory: (c: Category) => Promise<void>;
  deleteCategory: (id: string) => Promise<void>;
  getSummary: () => FinancialSummary;
}

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const FinanceProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [accounts, setAccounts] = useState<Account[]>([]);
  const [associationName, setAssociationName] = useState('Associação Integrada');
  const [loading, setLoading] = useState(true);

  const fetchInitialData = async () => {
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;

      // Fetch profiles/settings
      const { data: profile } = await supabase.from('profiles').select('*').eq('id', user.id).single();
      if (profile) {
        setAssociationName(profile.association_name || 'Associação Integrada');
      }

      // Fetch accounts
      const { data: accs } = await supabase.from('accounts').select('*').eq('user_id', user.id);
      if (accs) setAccounts(accs);

      // Fetch categories
      const { data: cats } = await supabase.from('categories').select('*').eq('user_id', user.id);
      if (cats) setCategories(cats);

      // Fetch transactions
      const { data: trans } = await supabase.from('transactions').select('*').eq('user_id', user.id).order('date', { ascending: false });
      if (trans) setTransactions(trans);

    } catch (error) {
      console.error('Error fetching data:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchInitialData();
  }, []);

  const updateAssociationName = async (name: string) => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;

    const { error } = await supabase.from('profiles').upsert({ id: user.id, association_name: name });
    if (!error) setAssociationName(name);
  };

  const addTransaction = async (t: Omit<Transaction, 'id'>) => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;

    const { data, error } = await supabase.from('transactions').insert([{ ...t, user_id: user.id }]).select().single();
    if (!error && data) setTransactions(prev => [data, ...prev]);
  };

  const updateTransaction = async (updated: Transaction) => {
    const { error } = await supabase.from('transactions').update(updated).eq('id', updated.id);
    if (!error) setTransactions(prev => prev.map(t => t.id === updated.id ? updated : t));
  };

  const deleteTransaction = async (id: string) => {
    const { error } = await supabase.from('transactions').delete().eq('id', id);
    if (!error) setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const addAccount = async (a: Omit<Account, 'id'>) => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;

    const { data, error } = await supabase.from('accounts').insert([{ ...a, user_id: user.id }]).select().single();
    if (!error && data) setAccounts(prev => [...prev, data]);
  };

  const updateAccount = async (updated: Account) => {
    const { error } = await supabase.from('accounts').update(updated).eq('id', updated.id);
    if (!error) setAccounts(prev => prev.map(a => a.id === updated.id ? updated : a));
  };

  const deleteAccount = async (id: string) => {
    const { error } = await supabase.from('accounts').delete().eq('id', id);
    if (!error) setAccounts(prev => prev.filter(a => a.id !== id));
  };

  const addCategory = async (c: Omit<Category, 'id'>) => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;

    const { data, error } = await supabase.from('categories').insert([{ ...c, user_id: user.id }]).select().single();
    if (!error && data) setCategories(prev => [...prev, data]);
  };

  const updateCategory = async (updated: Category) => {
    const { error } = await supabase.from('categories').update(updated).eq('id', updated.id);
    if (!error) setCategories(prev => prev.map(c => c.id === updated.id ? updated : c));
  };

  const deleteCategory = async (id: string) => {
    const { error } = await supabase.from('categories').delete().eq('id', id);
    if (!error) setCategories(prev => prev.filter(c => c.id !== id));
  };

  const getSummary = (): FinancialSummary => {
    return transactions.reduce((acc, t) => {
      const isIncome = t.type === 'income';
      const isCompleted = t.status === 'completed';

      if (isIncome) {
        if (isCompleted) acc.totalIncome += t.amount;
        else acc.pendingIncome += t.amount;
      } else {
        if (isCompleted) acc.totalExpense += t.amount;
        else acc.pendingExpense += t.amount;
      }

      if (isCompleted) {
        acc.balance += isIncome ? t.amount : -t.amount;
      }

      return acc;
    }, {
      totalIncome: 0,
      totalExpense: 0,
      balance: 0,
      pendingIncome: 0,
      pendingExpense: 0
    });
  };

  return (
    <FinanceContext.Provider value={{
      transactions,
      categories,
      accounts,
      associationName,
      loading,
      updateAssociationName,
      addTransaction,
      updateTransaction,
      deleteTransaction,
      addAccount,
      updateAccount,
      deleteAccount,
      addCategory,
      updateCategory,
      deleteCategory,
      getSummary,
    }}>
      {children}
    </FinanceContext.Provider>
  );
};

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error('useFinance must be used within a FinanceProvider');
  return context;
};

