                                            {t.attachment ? (
                                                <>
                                                    <span className="truncate max-w-[150px]">{t.attachment}</span>
                                                    <span className="text-xs bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400 px-2 py-0.5 rounded">Arquivo</span>
