                                    </div>
                                </div>
                            </td>
                        </tr>
                    )}
                </React.Fragment>
              ))}
              {filteredTransactions.length === 0 && (
                <tr>
                    <td colSpan={8} className="px-6 py-12 text-center text-slate-500">
                        Nenhuma transação encontrada para os filtros selecionados.
                    </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

