                    {selectedDoc.type === 'oficio' ? `OFÍCIO Nº ${selectedDoc.content.number || '___'}` : 
                     selectedDoc.type === 'comissao' ? `PORTARIA DE COMISSÃO: ${selectedDoc.title}` : 
                     `ESCALA DE SERVIÇO: ${selectedDoc.title}`}
