import React, { useState } from 'react';
import { useFinance } from '../context/FinanceContext';
import { Transaction, TransactionType, PaymentMethod } from '../types';
import { Plus, Search, CheckCircle, Clock, FileSpreadsheet, ChevronDown, ChevronUp, CreditCard, StickyNote, Trash2, Pencil, Upload, Paperclip, X, Tag, Landmark } from 'lucide-react';

const TransactionManager: React.FC = () => {
  const { transactions, addTransaction, updateTransaction, deleteTransaction, categories, accounts, addCategory } = useFinance();
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [filterType, setFilterType] = useState<'all' | TransactionType>('all');
  const [filterAccountId, setFilterAccountId] = useState<string>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [showCategoryForm, setShowCategoryForm] = useState(false);
  const [newCategoryName, setNewCategoryName] = useState('');

  // Form State
  const [formData, setFormData] = useState({
    description: '',
    amount: '',
    date: new Date().toISOString().split('T')[0],
    type: 'expense' as TransactionType,
    category: '',
    accountId: '',
    status: 'completed' as const,
    paymentMethod: 'bank_transfer' as PaymentMethod,
    notes: '',
    attachment: null as File | null,
    attachmentName: ''
  });

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFormData({
        ...formData,
        attachment: e.target.files[0],
        attachmentName: e.target.files[0].name
      });
    }
  };

  const resetForm = () => {
    setFormData({
      description: '',
      amount: '',
      date: new Date().toISOString().split('T')[0],
      type: 'expense',
      category: '',
      accountId: '',
      status: 'completed',
      paymentMethod: 'bank_transfer',
      notes: '',
      attachment: null,
      attachmentName: ''
    });
    setShowForm(false);
    setEditingId(null);
  };

  const handleEdit = (e: React.MouseEvent, t: Transaction) => {
    e.stopPropagation();
    setEditingId(t.id);
    setFormData({
      description: t.description,
      amount: t.amount.toString(),
      date: t.date,
      type: t.type,
      category: t.category,
      accountId: t.accountId,
      status: t.status as any,
      paymentMethod: t.paymentMethod,
      notes: t.notes || '',
      attachment: null,
      attachmentName: t.attachment || ''
    });
    setShowForm(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.description || !formData.amount || !formData.category || !formData.accountId) {
        alert("Por favor, preencha todos os campos obrigatórios.");
        return;
    }

    if (editingId) {
      updateTransaction({
        id: editingId,
        description: formData.description,
        amount: parseFloat(formData.amount),
        date: formData.date,
        type: formData.type,
        category: formData.category,
        accountId: formData.accountId,
        status: formData.status,
        paymentMethod: formData.paymentMethod,
        notes: formData.notes,
        attachment: formData.attachmentName,
        reconciled: transactions.find(t => t.id === editingId)?.reconciled || false
      });
    } else {
      addTransaction({
        description: formData.description,
        amount: parseFloat(formData.amount),
        date: formData.date,
        type: formData.type,
        category: formData.category,
        accountId: formData.accountId,
        status: formData.status,
        paymentMethod: formData.paymentMethod,
        notes: formData.notes,
        attachment: formData.attachmentName,
        reconciled: false
      });
    }

    resetForm();
  };

  const handleAddCategory = () => {
    if (!newCategoryName) return;
    addCategory({
        name: newCategoryName,
        type: formData.type
    });
    setFormData({...formData, category: newCategoryName});
    setNewCategoryName('');
    setShowCategoryForm(false);
  };

  const handleReconcile = (e: React.MouseEvent, t: Transaction) => {
    e.stopPropagation();
    updateTransaction({ ...t, reconciled: !t.reconciled });
  };

  const handleDelete = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      if(window.confirm('Tem certeza que deseja excluir esta transação?')) {
          deleteTransaction(id);
      }
  }

  const toggleExpand = (id: string) => {
    setExpandedId(prev => prev === id ? null : id);
  };

  const filteredTransactions = transactions.filter(t => {
    const matchesType = filterType === 'all' || t.type === filterType;
    const matchesAccount = filterAccountId === 'all' || t.accountId === filterAccountId;
    const matchesSearch = t.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          t.category.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesType && matchesSearch && matchesAccount;
  });

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const getPaymentMethodLabel = (method: PaymentMethod) => {
      const labels: Record<PaymentMethod, string> = {
          bank_transfer: 'Transferência Bancária',
          credit_card: 'Cartão de Crédito',
          cash: 'Dinheiro',
          check: 'Cheque',
          pix: 'PIX'
      };
      return labels[method] || method;
  };

  const getAccountName = (id: string) => {
      return accounts.find(a => a.id === id)?.name || 'Conta Excluída';
  }

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
           <h2 className="text-2xl font-bold text-blue-900">Fluxo de Caixa</h2>
           <p className="text-slate-500">Gestão de Entradas e Saídas</p>
        </div>
        <button 
          onClick={() => { if(showForm && !editingId) setShowForm(false); else { resetForm(); setShowForm(true); } }}
          className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors shadow-md"
        >
          {showForm && !editingId ? <X size={20} /> : <Plus size={20} />}
          {showForm && !editingId ? 'Fechar' : 'Nova Transação'}
        </button>
      </div>

      {showForm && (
        <div className="bg-white p-6 rounded-xl shadow-lg border border-blue-100 animate-in fade-in slide-in-from-top-4">
          <h3 className="text-lg font-bold text-blue-900 mb-4">{editingId ? 'Editar Transação' : 'Adicionar Transação'}</h3>
          <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            <div className="col-span-2">
              <label className="block text-sm font-medium text-slate-700 mb-1">Descrição</label>
              <input 
                type="text" 
                required
                className="w-full border border-slate-200 rounded-lg p-2 bg-slate-50 focus:ring-2 focus:ring-blue-500 outline-none"
                value={formData.description}
                onChange={e => setFormData({...formData, description: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Valor (R$)</label>
              <input 
                type="number" 
                step="0.01"
                required
                className="w-full border border-slate-200 rounded-lg p-2 bg-slate-50 focus:ring-2 focus:ring-blue-500 outline-none"
                value={formData.amount}
                onChange={e => setFormData({...formData, amount: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Data</label>
              <input 
                type="date" 
                required
                className="w-full border border-slate-200 rounded-lg p-2 bg-slate-50 focus:ring-2 focus:ring-blue-500 outline-none"
                value={formData.date}
                onChange={e => setFormData({...formData, date: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Tipo</label>
              <select 
                className="w-full border border-slate-200 rounded-lg p-2 bg-slate-50 focus:ring-2 focus:ring-blue-500 outline-none"
                value={formData.type}
                onChange={e => setFormData({...formData, type: e.target.value as TransactionType, category: ''})}
              >
                <option value="income">Receita</option>
                <option value="expense">Despesa</option>
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1 flex justify-between">
                Categoria
                <button 
