               <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Nome Oficial da Associação</label>
                  <input 
                    type="text" 
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-800"
                    value={localAssocName}
                    onChange={e => setLocalAssocName(e.target.value)}
                  />
               </div>
               <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">CNPJ</label>
                  <input 
                    type="text" 
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-800"
                    value={cnpj}
                    onChange={e => setCnpj(e.target.value)}
                  />
               </div>
            </div>

            <div className="pt-4 border-t border-slate-100 flex justify-end">
               <button 
                  type="submit" 
                  className="bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 px-8 rounded-xl flex items-center gap-2 transition-all shadow-lg shadow-blue-900/10"
               >
                  <Save size={18} />
                  Salvar Mudanças
               </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

export default Settings;

import React, { useState } from 'react';
import { Mail, Lock, User, ArrowRight, ShieldCheck, AlertCircle } from 'lucide-react';
import { supabase } from '../services/supabaseClient';

interface LoginProps {
  onLogin: () => void;
}

const Login: React.FC<LoginProps> = () => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      if (isRegistering) {
        const { error } = await supabase.auth.signUp({
          email,
          password,
          options: {
            data: { full_name: name }
          }
        });
        if (error) throw error;
        alert("Cadastro realizado! Verifique seu e-mail para confirmar.");
      } else {
        const { error } = await supabase.auth.signInWithPassword({
          email,
          password,
        });
        if (error) throw error;
      }
    } catch (err: any) {
      setError(err.message || 'Erro ao processar solicitação');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden -z-10 pointer-events-none">
        <div className="absolute top-[-10%] left-[-5%] w-[40%] h-[40%] bg-blue-100 rounded-full blur-3xl opacity-50"></div>
        <div className="absolute bottom-[-10%] right-[-5%] w-[40%] h-[40%] bg-blue-200 rounded-full blur-3xl opacity-50"></div>
      </div>

      <div className="w-full max-w-md bg-white rounded-2xl shadow-2xl border border-blue-50 overflow-hidden relative">
        <div className="p-8">
          <div className="flex justify-center mb-6">
            <div className="bg-blue-600 w-12 h-12 rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-200">
              <ShieldCheck size={28} />
            </div>
          </div>

          <div className="text-center mb-8">
            <h1 className="text-2xl font-bold text-blue-900 tracking-tight">
              {isRegistering ? 'Criar sua conta' : 'Gestão Integrada Pro'}
            </h1>
            <p className="text-slate-500 mt-2">
              {isRegistering 
                ? 'Comece a gerir sua associação hoje mesmo' 
                : 'Acesse sua Gestão Integrada Pro'}
            </p>
          </div>

          {error && (
            <div className="mb-6 p-3 bg-red-50 border border-red-100 text-red-600 rounded-xl flex items-center gap-2 text-sm animate-in fade-in zoom-in">
              <AlertCircle size={18} />
              {error}
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-4">
            {isRegistering && (
              <div className="relative">
                <label className="text-xs font-semibold text-blue-800 uppercase tracking-wider mb-1 block ml-1">Nome Completo</label>
                <div className="relative group">
                  <User className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-500 transition-colors" size={18} />
                  <input 
                    type="text" 
                    required
                    placeholder="João Silva"
                    className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all text-slate-700"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                  />
                </div>
              </div>
            )}

            <div className="relative">
              <label className="text-xs font-semibold text-blue-800 uppercase tracking-wider mb-1 block ml-1">E-mail</label>
              <div className="relative group">
                <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-500 transition-colors" size={18} />
                <input 
                  type="email" 
                  required
                  placeholder="seu@email.com"
                  className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all text-slate-700"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                />
              </div>
            </div>

            <div className="relative">
              <label className="text-xs font-semibold text-blue-800 uppercase tracking-wider mb-1 block ml-1">Senha</label>
              <div className="relative group">
                <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-500 transition-colors" size={18} />
                <input 
                  type="password" 
                  required
                  placeholder="••••••••"
                  className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all text-slate-700"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                />
              </div>
            </div>

            <button 
              type="submit" 
              disabled={loading}
              className="w-full bg-blue-900 hover:bg-blue-950 disabled:opacity-50 text-white font-bold py-3 px-4 rounded-xl shadow-lg flex items-center justify-center gap-2 group transition-all"
            >
              {loading ? (
                <div className="h-5 w-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
              ) : (
                <>
                  {isRegistering ? 'Registrar' : 'Entrar no Sistema'}
                  <ArrowRight size={18} className="group-hover:translate-x-1 transition-transform" />
                </>
              )}
            </button>
          </form>

          <div className="mt-8 pt-6 border-t border-blue-50 text-center">
            <p className="text-slate-500 text-sm">
              {isRegistering ? 'Já possui uma conta?' : 'Ainda não tem conta?'}
              <button 
                onClick={() => setIsRegistering(!isRegistering)}
                className="ml-1 text-blue-600 font-bold hover:underline"
              >
                {isRegistering ? 'Faça login' : 'Cadastre sua conta'}
              </button>
            </p>
          </div>
        </div>
        <div className="bg-blue-50 px-8 py-4 flex items-center justify-center gap-2 border-t border-blue-100">
          <span className="text-[10px] text-blue-400 font-bold uppercase tracking-widest">Gestão Integrada Pro v2.5</span>
        </div>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import TransactionManager from './components/TransactionManager';
import Reports from './components/Reports';
import Documents from './components/Documents';
import AccountManager from './components/AccountManager';
import BoardManager from './components/BoardManager';
import ProjectManager from './components/ProjectManager';
import Settings from './components/Settings';
import Login from './components/Login';
import { FinanceProvider } from './context/FinanceContext';
import { supabase } from './services/supabaseClient';

const Payables = () => (
    <div className="space-y-6">
        <div className="bg-amber-50 border-l-4 border-amber-400 p-4 shadow-sm">
            <p className="text-sm text-amber-700 font-medium">
                <strong>Nota:</strong> Esta visualização filtra automaticamente transações pendentes.
            </p>
        </div>
        <TransactionManager />
    </div>
);

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Check current session
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setLoading(false);
    });

    // Listen for auth changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    return () => subscription.unsubscribe();
  }, []);

  if (loading) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  if (!session) {
    return <Login onLogin={() => {}} />; 
  }

  return (
    <FinanceProvider>
        <HashRouter>
            <Routes>
                <Route path="/" element={<Layout />}>
                    <Route index element={<Dashboard />} />
                    {/* Financeiro */}
                    <Route path="accounts" element={<AccountManager />} />
                    <Route path="transactions" element={<TransactionManager />} />
                    <Route path="payables" element={<Payables />} />
                    <Route path="reports" element={<Reports />} />
                    {/* Secretaria */}
                    <Route path="board" element={<BoardManager />} />
                    <Route path="projects" element={<ProjectManager />} />
                    <Route path="documents" element={<Documents />} />
                    {/* Geral */}
                    <Route path="settings" element={<Settings />} />
                    <Route path="*" element={<Navigate to="/" replace />} />
                </Route>
            </Routes>
        </HashRouter>
    </FinanceProvider>
  );
};

export default App;

import React, { useState } from 'react';
import { useFinance } from '../context/FinanceContext';
import { Account } from '../types';
import { Plus, Wallet, Landmark, PiggyBank, Trash2, Pencil, X } from 'lucide-react';

const AccountManager: React.FC = () => {
  const { accounts, addAccount, updateAccount, deleteAccount, transactions } = useFinance();
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    name: '',
    type: 'bank' as const,
    initialBalance: '',
    description: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name) return;

    if (editingId) {
      updateAccount({
        id: editingId,
        name: formData.name,
        type: formData.type,
        initialBalance: parseFloat(formData.initialBalance) || 0,
        description: formData.description
      });
    } else {
      addAccount({
        name: formData.name,
        type: formData.type,
        initialBalance: parseFloat(formData.initialBalance) || 0,
        description: formData.description
      });
    }

    resetForm();
  };

  const resetForm = () => {
    setFormData({ name: '', type: 'bank', initialBalance: '', description: '' });
    setShowForm(false);
    setEditingId(null);
  };

  const handleEdit = (account: Account) => {
    setEditingId(account.id);
    setFormData({
      name: account.name,
      type: account.type,
      initialBalance: account.initialBalance.toString(),
      description: account.description || ''
    });
    setShowForm(true);
  };

  const calculateCurrentBalance = (accountId: string, initialBalance: number) => {
    const accountTransactions = transactions.filter(t => t.accountId === accountId && t.status === 'completed');
    const total = accountTransactions.reduce((acc, t) => {
        return acc + (t.type === 'income' ? t.amount : -t.amount);
    }, 0);
    return initialBalance + total;
  };

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const getIcon = (type: Account['type']) => {
    switch(type) {
        case 'bank': return <Landmark size={24} className="text-blue-600" />;
        case 'cash': return <Wallet size={24} className="text-blue-500" />;
        case 'savings': return <PiggyBank size={24} className="text-blue-400" />;
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
           <h2 className="text-2xl font-bold text-blue-900">Cadastro de Caixas & Contas</h2>
           <p className="text-slate-500">Gerencie contas bancárias e caixas físicos</p>
        </div>
        <button 
          onClick={() => { if(showForm && !editingId) setShowForm(false); else { resetForm(); setShowForm(true); } }}
          className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors shadow-md"
        >
          {showForm && !editingId ? <X size={20} /> : <Plus size={20} />}
          {showForm && !editingId ? 'Fechar' : 'Nova Conta'}
        </button>
      </div>

      {showForm && (
        <div className="bg-white p-6 rounded-xl shadow-lg border border-blue-50 animate-in fade-in slide-in-from-top-4">
          <h3 className="text-lg font-bold text-blue-900 mb-4">
            {editingId ? 'Editar Conta/Caixa' : 'Cadastrar Nova Conta/Caixa'}
          </h3>
          <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="col-span-1 md:col-span-2">
              <label className="block text-sm font-medium text-slate-700 mb-1">Nome da Conta</label>
              <input 
                type="text" 
                required
                placeholder="Ex: Banco do Brasil, Caixinha do Café..."
                className="w-full border border-slate-200 bg-slate-50 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none"
                value={formData.name}
                onChange={e => setFormData({...formData, name: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Tipo</label>
              <select 
                className="w-full border border-slate-200 bg-slate-50 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none"
                value={formData.type}
                onChange={e => setFormData({...formData, type: e.target.value as any})}
              >
                <option value="bank">Conta Bancária</option>
                <option value="cash">Caixa Físico (Dinheiro)</option>
                <option value="savings">Aplicação/Poupança</option>
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Saldo Inicial</label>
              <input 
                type="number" 
                step="0.01"
                required
                className="w-full border border-slate-200 bg-slate-50 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none"
                value={formData.initialBalance}
                onChange={e => setFormData({...formData, initialBalance: e.target.value})}
              />
            </div>
            <div className="col-span-1 md:col-span-2">
              <label className="block text-sm font-medium text-slate-700 mb-1">Descrição</label>
              <input 
                type="text" 
                className="w-full border border-slate-200 bg-slate-50 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none"
                value={formData.description}
                onChange={e => setFormData({...formData, description: e.target.value})}
              />
            </div>
            <div className="col-span-1 md:col-span-2 flex justify-end gap-3 mt-4">
               <button 
                type="button" 
                onClick={resetForm}
                className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg font-medium"
              >
                Cancelar
              </button>
              <button 
                type="submit" 
                className="px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg shadow-md font-bold"
              >
                {editingId ? 'Atualizar Conta' : 'Salvar Conta'}
              </button>
            </div>
          </form>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {accounts.map(account => {
            const currentBalance = calculateCurrentBalance(account.id, account.initialBalance);
            return (
                <div key={account.id} className="bg-white p-6 rounded-xl shadow-sm border border-blue-50 hover:shadow-md transition-shadow relative group">
                    <div className="flex justify-between items-start mb-4">
                        <div className="flex items-center gap-3">
                            <div className="p-3 bg-blue-50 rounded-lg">
                                {getIcon(account.type)}
                            </div>
                            <div>
                                <h3 className="font-bold text-blue-900">{account.name}</h3>
                                <p className="text-xs text-slate-500">{account.description || 'Sem descrição'}</p>
                            </div>
                        </div>
                        <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                            <button 
                                onClick={() => handleEdit(account)}
                                className="text-slate-400 hover:text-blue-600 p-1"
                                title="Editar Conta"
                            >
                                <Pencil size={18} />
                            </button>
                            <button 
                                onClick={() => { if(window.confirm('Excluir esta conta?')) deleteAccount(account.id); }}
                                className="text-slate-400 hover:text-red-500 p-1"
                                title="Excluir Conta"
                            >
                                <Trash2 size={18} />
                            </button>
                        </div>
                    </div>

                    <div className="space-y-3">
                        <div className="flex justify-between text-sm">
                            <span className="text-slate-500">Saldo Inicial:</span>
                            <span className="font-medium text-slate-700">{formatCurrency(account.initialBalance)}</span>
                        </div>
                        <div className="pt-3 border-t border-blue-50">
                             <p className="text-xs text-slate-400 uppercase tracking-wider mb-1">Saldo Atual</p>
                             <p className={`text-2xl font-bold ${currentBalance >= 0 ? 'text-blue-700' : 'text-red-600'}`}>
                                {formatCurrency(currentBalance)}
                             </p>
                        </div>
                    </div>
                </div>
            );
        })}
      </div>
    </div>
  );
};

export default AccountManager;

import React, { useState } from 'react';
import { useFinance } from '../context/FinanceContext';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';
import { Printer, Calendar, Landmark, FileText, Download } from 'lucide-react';

const COLORS = ['#1e40af', '#2563eb', '#3b82f6', '#60a5fa', '#93c5fd', '#bfdbfe'];

const Reports: React.FC = () => {
  const { transactions, categories, accounts } = useFinance();

  // State for Report Filters
  const [dateRange, setDateRange] = useState({
    start: new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0],
    end: new Date().toISOString().split('T')[0]
  });
  const [selectedAccountId, setSelectedAccountId] = useState<string>('all');

  // Report Generation Logic
  const reportTransactions = transactions
    .filter(t => {
        const matchesDate = t.date >= dateRange.start && t.date <= dateRange.end;
        const matchesAccount = selectedAccountId === 'all' || t.accountId === selectedAccountId;
        return matchesDate && matchesAccount;
    })
    .sort((a, b) => a.date.localeCompare(b.date));

  const reportSummary = reportTransactions.reduce((acc, t) => {
    if (t.type === 'income') acc.income += t.amount;
    else acc.expense += t.amount;
    return acc;
  }, { income: 0, expense: 0 });

  // Calculate data for Pie Chart (Expenses by Category)
  const expensesByCategory = categories
    .filter(c => c.type === 'expense')
    .map(c => {
      const total = reportTransactions
        .filter(t => t.category === c.name && t.type === 'expense')
        .reduce((sum, t) => sum + t.amount, 0);
      return { name: c.name, value: total };
    })
    .filter(item => item.value > 0);

  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const formatDate = (dateStr: string) => {
    if (!dateStr) return '';
    const [year, month, day] = dateStr.split('-');
    return `${day}/${month}/${year}`;
  };

  const handlePrint = () => {
    window.print();
  };

  const handleExportCSV = () => {
    const headers = ['Data', 'Descricao', 'Categoria', 'Conta', 'Valor', 'Tipo', 'Status'];
    const rows = reportTransactions.map(t => [
        t.date,
        `"${t.description.replace(/"/g, '""')}"`,
        `"${t.category}"`,
        `"${getAccountName(t.accountId)}"`,
        t.amount.toFixed(2),
        t.type === 'income' ? 'Entrada' : 'Saida',
        t.status === 'completed' ? 'Concluido' : 'Pendente'
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
        + [headers.join(','), ...rows.map(r => r.join(','))].join('\n');

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `relatorio_tesouraria_${dateRange.start}_a_${dateRange.end}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const getAccountName = (id: string) => accounts.find(a => a.id === id)?.name || 'Todos';

  return (
    <div className="space-y-8">
      {/* Print CSS Styles */}
      <style>{`
        @media print {
          body * {
            visibility: hidden;
          }
          #printable-report, #printable-report * {
            visibility: visible;
          }
          #printable-report {
            position: absolute;
            left: 0;
            top: 0;
            width: 100%;
            background: white;
            padding: 20px;
            z-index: 9999;
          }
          nav, aside, header, .no-print {
            display: none !important;
          }
        }
      `}</style>

      <div className="no-print">
         <h2 className="text-2xl font-bold text-blue-900">Relatórios Gerenciais</h2>
         <p className="text-slate-500">Visualização de despesas e exportação de demonstrativos</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 no-print">
        {/* Expense Distribution */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-blue-50">
            <h3 className="text-lg font-bold text-blue-900 mb-4">Distribuição de Despesas</h3>
            <div className="h-72">
                <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                        <Pie
                            data={expensesByCategory}
                            cx="50%"
                            cy="50%"
                            innerRadius={60}
                            outerRadius={80}
                            fill="#3b82f6"
                            paddingAngle={5}
                            dataKey="value"
                        >
                            {expensesByCategory.map((entry, index) => (
                                <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                            ))}
                        </Pie>
                        <Tooltip 
                            formatter={(value: number) => formatCurrency(value)}
                            contentStyle={{ backgroundColor: '#1e3a8a', border: 'none', borderRadius: '8px', color: '#fff' }}
                        />
                        <Legend />
                    </PieChart>
                </ResponsiveContainer>
            </div>
            {expensesByCategory.length === 0 && (
                <div className="text-center text-slate-400 py-20 text-sm italic">
                    Nenhuma despesa para os filtros selecionados.
                </div>
            )}
        </div>

        {/* Report Generation Section */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-blue-50 flex flex-col justify-between">
           <div>
               <h3 className="text-lg font-bold text-blue-900 flex items-center gap-2 mb-2">
                   <FileText size={20} className="text-blue-500"/> 
                   Parâmetros do Relatório
               </h3>
               <p className="text-sm text-slate-500 mb-6">Ajuste o período e as contas para gerar o documento.</p>

               <div className="space-y-4">
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-2">
                            <Calendar size={14} className="text-blue-500" /> Início
                        </label>
                        <input 
                            type="date" 
                            value={dateRange.start}
                            onChange={(e) => setDateRange({...dateRange, start: e.target.value})}
                            className="w-full border border-slate-200 bg-slate-50 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none"
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-2">
                            <Calendar size={14} className="text-blue-500" /> Fim
                        </label>
                        <input 
                            type="date" 
                            value={dateRange.end}
                            onChange={(e) => setDateRange({...dateRange, end: e.target.value})}
                            className="w-full border border-slate-200 bg-slate-50 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none"
                        />
                    </div>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-2">
                        <Landmark size={14} className="text-blue-500" /> Filtro de Conta
                    </label>
                    <select 
                        className="w-full border border-slate-200 bg-slate-50 rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none"
                        value={selectedAccountId}
                        onChange={(e) => setSelectedAccountId(e.target.value)}
                    >
                        <option value="all">Todas as Contas</option>
                        {accounts.map(acc => (
                            <option key={acc.id} value={acc.id}>{acc.name}</option>
                        ))}
                    </select>
                  </div>
               </div>
           </div>

           <div className="mt-8 pt-6 border-t border-blue-50 grid grid-cols-2 gap-4">
              <button 
                  onClick={handleExportCSV}
                  className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-3 rounded-lg flex items-center justify-center gap-2 transition-colors font-bold shadow-md"
              >
                  <Download size={18} />
                  Exportar CSV
              </button>
              <button 
                  onClick={handlePrint}
                  className="bg-blue-900 hover:bg-blue-950 text-white px-4 py-3 rounded-lg flex items-center justify-center gap-2 transition-colors font-bold shadow-md"
              >
                  <Printer size={18} />
                  Imprimir PDF
              </button>
           </div>
        </div>
      </div>

      {/* Hidden Printable Area */}
      <div id="printable-report" className="hidden">
        <div className="text-center mb-8 border-b-2 border-blue-900 pb-4">
            <h1 className="text-3xl font-bold text-blue-900 uppercase tracking-wide">Gestão Integrada Pro</h1>
            <h2 className="text-xl text-slate-700 mt-2">Demonstrativo Financeiro</h2>
            <p className="text-slate-500 mt-1 font-medium">
                Período: {formatDate(dateRange.start)} até {formatDate(dateRange.end)}
            </p>
            <p className="text-slate-500 font-medium">
                Conta: {selectedAccountId === 'all' ? 'Todas as Contas' : getAccountName(selectedAccountId)}
            </p>
        </div>

        <div className="mb-8">
            <h3 className="text-lg font-bold text-blue-900 mb-4 border-l-4 border-blue-600 pl-3 uppercase">Resumo do Período</h3>
            <div className="grid grid-cols-3 gap-4">
                <div className="p-4 bg-blue-50 border border-blue-100 rounded">
                    <p className="text-xs text-blue-600 font-bold uppercase tracking-wider">Total Entradas</p>
                    <p className="text-xl font-bold text-blue-700">{formatCurrency(reportSummary.income)}</p>
                </div>
                <div className="p-4 bg-red-50 border border-red-100 rounded">
                    <p className="text-xs text-red-600 font-bold uppercase tracking-wider">Total Saídas</p>
                    <p className="text-xl font-bold text-red-700">{formatCurrency(reportSummary.expense)}</p>
                </div>
                <div className="p-4 bg-gray-50 border border-gray-200 rounded">
                    <p className="text-xs text-gray-500 font-bold uppercase tracking-wider">Resultado</p>
                    <p className={`text-xl font-bold ${reportSummary.income - reportSummary.expense >= 0 ? 'text-blue-700' : 'text-red-700'}`}>
                        {formatCurrency(reportSummary.income - reportSummary.expense)}
                    </p>
                </div>
            </div>
        </div>

        <div className="mb-12">
            <h3 className="text-lg font-bold text-blue-900 mb-4 border-l-4 border-blue-900 pl-3 uppercase">Detalhamento das Operações</h3>
            <table className="w-full text-sm text-left border-collapse">
                <thead>
                    <tr className="bg-blue-50 border-b-2 border-blue-200">
                        <th className="px-4 py-2 text-blue-900">Data</th>
                        <th className="px-4 py-2 text-blue-900">Descrição</th>
                        <th className="px-4 py-2 text-blue-900">Categoria</th>
                        <th className="px-4 py-2 text-blue-900">Conta</th>
                        <th className="px-4 py-2 text-blue-900 text-right">Valor</th>
                    </tr>
                </thead>
                <tbody>
                    {reportTransactions.map((t, idx) => (
                        <tr key={t.id} className={`border-b border-gray-100 ${idx % 2 === 0 ? 'bg-white' : 'bg-blue-50/20'}`}>
                            <td className="px-4 py-2 whitespace-nowrap">{formatDate(t.date)}</td>
                            <td className="px-4 py-2 font-medium">{t.description}</td>
                            <td className="px-4 py-2">{t.category}</td>
                            <td className="px-4 py-2">{getAccountName(t.accountId)}</td>
                            <td className={`px-4 py-2 text-right font-bold whitespace-nowrap ${t.type === 'income' ? 'text-blue-700' : 'text-red-700'}`}>
                                {t.type === 'income' ? '+' : '-'}{formatCurrency(t.amount)}
                            </td>
                        </tr>
                    ))}
                    {reportTransactions.length === 0 && (
                        <tr>
                            <td colSpan={5} className="text-center py-8 text-gray-400 italic">Nenhum dado encontrado para o período.</td>
                        </tr>
                    )}
                </tbody>
            </table>
        </div>

        <div className="mt-20 grid grid-cols-2 gap-20">
            <div className="text-center border-t border-slate-300 pt-4">
                <p className="font-bold text-slate-800">Assinatura Tesouraria</p>
                <p className="text-[10px] text-slate-400 uppercase tracking-widest mt-1">Carimbo e Assinatura</p>
            </div>
            <div className="text-center border-t border-slate-300 pt-4">
                <p className="font-bold text-slate-800">Responsável Legal</p>
                <p className="text-[10px] text-slate-400 uppercase tracking-widest mt-1">Carimbo e Assinatura</p>
            </div>
        </div>

        <div className="mt-8 text-center text-[10px] text-slate-300 italic">
            Gerado via Gestão Integrada Pro em {new Date().toLocaleString()}
        </div>
      </div>
    </div>
  );
};

export default Reports;

export type TransactionType = 'income' | 'expense';
export type TransactionStatus = 'pending' | 'completed' | 'cancelled';
export type PaymentMethod = 'bank_transfer' | 'credit_card' | 'cash' | 'check' | 'pix';
export type ProjectStatus = 'planned' | 'ongoing' | 'completed' | 'cancelled';
export type OfficialDocType = 'oficio' | 'comissao' | 'escala';

export interface Category {
  id: string;
  name: string;
  type: TransactionType;
  budgetLimit?: number;
}

export interface Account {
  id: string;
  name: string;
  type: 'bank' | 'cash' | 'savings';
  description?: string;
  initialBalance: number;
}

export interface Transaction {
  id: string;
  date: string;
  description: string;
  amount: number;
  type: TransactionType;
  category: string;
  accountId: string;
  status: TransactionStatus;
  paymentMethod: PaymentMethod;
  notes?: string;
  attachment?: string;
  reconciled: boolean;
}

export interface BoardMember {
  id: string;
  name: string;
  role: string;
  termStart: string;
  termEnd: string;
  phone?: string;
  email?: string;
}

export interface Project {
  id: string;
  title: string;
  description: string;
  objective: string;
  targetAudience: string;
  resources: string;
  financialImpact: number;
  executionDate: string;
  executionLocation: string;
  status: ProjectStatus;
}

export interface OfficialDocument {
  id: string;
  type: OfficialDocType;
  title: string;
  content: any;
  created_at: string;
}

export interface FinancialSummary {
  totalIncome: number;
  totalExpense: number;
  balance: number;
  pendingIncome: number;
  pendingExpense: number;
}

export interface AIAnalysisResult {
  summary: string;
  risks: string[];
  recommendations: string[];
  lastUpdated: string;
}

import React, { createContext, useContext, useState, ReactNode, useEffect } from 'react';
import { Transaction, Category, FinancialSummary, Account, BoardMember, Project, OfficialDocument } from '../types';
import { supabase } from '../services/supabaseClient';

interface DocumentMetadata {
  id: string;
  name: string;
  file_url: string;
  folder: string;
  created_at: string;
}

interface FinanceContextType {
  transactions: Transaction[];
  categories: Category[];
  accounts: Account[];
  documents: DocumentMetadata[];
  boardMembers: BoardMember[];
  projects: Project[];
  officialDocuments: OfficialDocument[];
  associationName: string;
  loading: boolean;
  updateAssociationName: (name: string) => Promise<void>;
  addTransaction: (t: Omit<Transaction, 'id'>) => Promise<void>;
  updateTransaction: (t: Transaction) => Promise<void>;
  deleteTransaction: (id: string) => Promise<void>;
  addAccount: (a: Omit<Account, 'id'>) => Promise<void>;
  updateAccount: (a: Account) => Promise<void>;
  deleteAccount: (id: string) => Promise<void>;
  addCategory: (c: Omit<Category, 'id'>) => Promise<void>;
  updateCategory: (id: string, name: string) => Promise<void>;
  deleteCategory: (id: string) => Promise<void>;
  addDocument: (name: string, url: string, folder: string) => Promise<void>;
  addBoardMember: (m: Omit<BoardMember, 'id'>) => Promise<void>;
  deleteBoardMember: (id: string) => Promise<void>;
  addProject: (p: Omit<Project, 'id'>) => Promise<void>;
  updateProject: (p: Project) => Promise<void>;
  deleteProject: (id: string) => Promise<void>;
  addOfficialDocument: (d: Omit<OfficialDocument, 'id' | 'created_at'>) => Promise<void>;
  deleteOfficialDocument: (id: string) => Promise<void>;
  fetchInitialData: () => Promise<void>;
  getSummary: () => FinancialSummary;
