import { GoogleGenAI, Type } from "@google/genai";
import { Transaction, AIAnalysisResult } from "../types";

export const analyzeFinancialHealth = async (transactions: Transaction[]): Promise<AIAnalysisResult> => {
  // Always initialize GoogleGenAI with process.env.API_KEY directly as per guidelines
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Filter last 50 transactions to keep context manageable
  const recentTransactions = transactions.slice(0, 50).map(t => ({
    date: t.date,
    type: t.type,
    amount: t.amount,
    category: t.category,
    status: t.status
  }));

  const prompt = `
    Atue como um tesoureiro sênior especialista em gestão de associações sem fins lucrativos.
    Analise os seguintes dados de transações financeiras recentes.

    Dados das Transações:
    ${JSON.stringify(recentTransactions)}

    Por favor, forneça uma análise estruturada contendo:
    1. Um resumo executivo da saúde financeira.
    2. Identificação de riscos financeiros (ex: liquidez, dependência de uma fonte de receita, gastos excessivos).
    3. Recomendações estratégicas para melhoria orçamentária e sustentabilidade.

    Retorne a resposta estritamente em formato JSON seguindo este esquema.
  `;

  try {
    // Using gemini-3-pro-preview for complex reasoning tasks
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING },
            risks: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
            recommendations: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
          },
          required: ["summary", "risks", "recommendations"],
          propertyOrdering: ["summary", "risks", "recommendations"]
        }
      }
    });

    // Directly access text property from the response object
    const result = JSON.parse(response.text || "{}");

    return {
      summary: result.summary || "Não foi possível gerar o resumo.",
      risks: result.risks || [],
      recommendations: result.recommendations || [],
      lastUpdated: new Date().toISOString()
    };

  } catch (error) {
    console.error("Erro ao analisar finanças com Gemini:", error);
    throw error;
  }
};

export type TransactionType = 'income' | 'expense';
export type TransactionStatus = 'pending' | 'completed' | 'cancelled';
export type PaymentMethod = 'bank_transfer' | 'credit_card' | 'cash' | 'check' | 'pix';
export type ProjectStatus = 'planned' | 'ongoing' | 'completed' | 'cancelled';
export type OfficialDocType = 'oficio' | 'comissao' | 'escala';

export interface Category {
  id: string;
  name: string;
  type: TransactionType;
  budgetLimit?: number;
}

export interface Account {
  id: string;
  name: string;
  type: 'bank' | 'cash' | 'savings';
  description?: string;
  initialBalance: number;
}

export interface Transaction {
  id: string;
  date: string;
  description: string;
  amount: number;
  type: TransactionType;
  category: string;
  accountId: string;
  status: TransactionStatus;
  paymentMethod: PaymentMethod;
  notes?: string;
  attachment?: string;
  reconciled: boolean;
}

export interface BoardMember {
  id: string;
  name: string;
  role: string;
  termStart: string;
  termEnd: string;
  phone?: string;
  email?: string;
}

export interface Project {
  id: string;
  title: string;
  description: string;
  objective: string;
  targetAudience: string;
  resources: string;
  financialImpact: number;
  executionDate: string;
  executionLocation: string;
  status: ProjectStatus;
  authorId?: string;
}

export interface OfficialDocument {
  id: string;
  type: OfficialDocType;
  title: string;
  content: any;
  created_at: string;
}

export interface FinancialSummary {
  totalIncome: number;
  totalExpense: number;
  balance: number;
  pendingIncome: number;
  pendingExpense: number;
}

export interface AIAnalysisResult {
  summary: string;
  risks: string[];
  recommendations: string[];
  lastUpdated: string;
}

