};

export default ProjectManager;

import React, { useState, useRef } from 'react';
import { useFinance } from '../context/FinanceContext';
import { 
  Building, 
  Save, 
  Tag, 
  Pencil, 
  Trash2, 
  X, 
  Check, 
  Database, 
  Download, 
  Upload, 
  RefreshCw,
  AlertTriangle,
  Loader2
} from 'lucide-react';

const Settings: React.FC = () => {
  const { 
    associationName, 
    updateAssociationName, 
    categories, 
    updateCategory, 
    deleteCategory,
    transactions,
    accounts,
    boardMembers,
    projects,
    officialDocuments,
    fetchInitialData,
    addTransaction,
    addAccount,
    addBoardMember,
    addProject,
    addCategory
  } = useFinance();

  const [localAssocName, setLocalAssocName] = useState(associationName);
  const [cnpj, setCnpj] = useState('00.000.000/0001-00');
  const [success, setSuccess] = useState(false);
  const [syncing, setSyncing] = useState(false);
  const [restoring, setRestoring] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const [editingCatId, setEditingCatId] = useState<string | null>(null);
  const [catTempName, setCatTempName] = useState('');

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    updateAssociationName(localAssocName);
    setSuccess(true);
    setTimeout(() => setSuccess(false), 3000);
  };

  const handleStartEditCat = (cat: any) => {
    setEditingCatId(cat.id);
    setCatTempName(cat.name);
  };

  const handleSaveCat = async () => {
    if (editingCatId && catTempName) {
        await updateCategory(editingCatId, catTempName);
        setEditingCatId(null);
    }
  };

  const handleManualSync = async () => {
    setSyncing(true);
    try {
      await fetchInitialData();
      alert("Sincronização com o banco de dados concluída!");
    } catch (error) {
      alert("Erro ao sincronizar dados.");
    } finally {
      setSyncing(false);
    }
  };

  const handleExportBackup = () => {
    const dataToExport = {
      associationName,
      exportDate: new Date().toISOString(),
      categories,
      accounts,
      transactions,
      boardMembers,
      projects,
      officialDocuments
    };

    const blob = new Blob([JSON.stringify(dataToExport, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `backup_${associationName.replace(/\s+/g, '_').toLowerCase()}_${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleImportRestore = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const confirmRestore = window.confirm(
      "Atenção: A restauração irá importar os dados do arquivo para o banco de dados atual. " +
      "Isso pode gerar duplicidade de registros se os dados já existirem. Deseja continuar?"
    );

    if (!confirmRestore) {
      if (fileInputRef.current) fileInputRef.current.value = '';
      return;
    }

    setRestoring(true);
    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const content = e.target?.result as string;
        const backup = JSON.parse(content);

        if (!backup.categories || !backup.accounts) {
          throw new Error("Arquivo de backup inválido.");
        }

        for (const cat of backup.categories) {
          await addCategory({ name: cat.name, type: cat.type, budgetLimit: cat.budgetLimit });
        }
        for (const acc of backup.accounts) {
          await addAccount({ name: acc.name, type: acc.type, initialBalance: acc.initialBalance, description: acc.description });
        }
        if (backup.boardMembers) {
          for (const member of backup.boardMembers) {
            await addBoardMember({ 
              name: member.name, role: member.role, 
              termStart: member.termStart, termEnd: member.termEnd, 
              phone: member.phone, email: member.email 
            });
          }
        }
        if (backup.projects) {
          for (const proj of backup.projects) {
            await addProject({ 
              title: proj.title, description: proj.description, 
              objective: proj.objective, targetAudience: proj.targetAudience,
              resources: proj.resources, financialImpact: proj.financialImpact,
              executionDate: proj.executionDate, executionLocation: proj.executionLocation,
              status: proj.status
              // Campo authorId removido da restauração para compatibilidade com o banco
            });
          }
        }
        if (backup.transactions) {
          for (const trans of backup.transactions) {
            await addTransaction({
              date: trans.date, description: trans.description, amount: trans.amount,
              type: trans.type, category: trans.category, accountId: trans.accountId,
              status: trans.status, paymentMethod: trans.paymentMethod, notes: trans.notes,
              attachment: trans.attachment, reconciled: trans.reconciled
            });
          }
        }

        alert("Restauração concluída com sucesso! Recarregando dados...");
        await fetchInitialData();
      } catch (err: any) {
        alert("Erro na restauração: " + err.message);
      } finally {
        setRestoring(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4">
      <div className="flex justify-between items-center">
        <div>
           <h2 className="text-2xl font-bold text-blue-900">Configurações</h2>
           <p className="text-slate-500">Personalize o ambiente e gerencie a segurança dos seus dados</p>
        </div>
        {success && (
          <div className="bg-emerald-100 text-emerald-700 px-4 py-2 rounded-lg flex items-center gap-2 border border-emerald-200 animate-in zoom-in">
            <Check size={18} />
            Alterações salvas!
          </div>
        )}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-blue-50 flex flex-col h-full">
          <div className="flex items-center gap-3 mb-6">
            <div className="p-2 bg-blue-100 text-blue-600 rounded-lg">
              <Building size={20} />
            </div>
            <h3 className="font-bold text-blue-900 text-lg">Informações da Entidade</h3>
          </div>

          <form onSubmit={handleSave} className="space-y-6 flex-1 flex flex-col justify-between">
            <div className="space-y-4">
               <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Nome Oficial da Associação</label>
                  <input 
                    type="text" 
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-800"
                    value={localAssocName}
                    onChange={e => setLocalAssocName(e.target.value)}
                  />
               </div>
               <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">CNPJ</label>
                  <input 
                    type="text" 
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-800"
                    value={cnpj}
                    onChange={e => setCnpj(e.target.value)}
                  />
               </div>
            </div>

            <div className="pt-4 border-t border-slate-100 flex justify-end">
               <button 
                  type="submit" 
                  className="bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 px-8 rounded-xl flex items-center gap-2 transition-all shadow-lg shadow-blue-900/10"
               >
                  <Save size={18} />
                  Salvar Mudanças
               </button>
            </div>
          </form>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-blue-50">
           <div className="flex items-center gap-3 mb-6">
              <div className="p-2 bg-emerald-100 text-emerald-600 rounded-lg">
                <Database size={20} />
              </div>
              <h3 className="font-bold text-blue-900 text-lg">Gestão de Dados & Sincronização</h3>
           </div>

           <div className="space-y-6">
              <div className="p-4 bg-amber-50 rounded-xl border border-amber-100 flex gap-3">
                 <AlertTriangle className="text-amber-600 flex-shrink-0" size={20} />
                 <p className="text-xs text-amber-800 leading-relaxed">
                   <strong>Atenção:</strong> O backup exporta apenas dados de texto e registros. Arquivos anexados (comprovantes) devem ser salvos separadamente no seu armazenamento em nuvem.
                 </p>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                 <button 
                    onClick={handleExportBackup}
                    className="flex items-center gap-3 p-4 bg-slate-50 hover:bg-slate-100 border border-slate-200 rounded-xl transition-all group"
                 >
                    <div className="p-2 bg-white rounded-lg text-blue-600 shadow-sm group-hover:scale-110 transition-transform">
                       <Download size={20} />
                    </div>
                    <div className="text-left">
                       <p className="font-bold text-slate-800 text-sm">Fazer Backup</p>
                       <p className="text-[10px] text-slate-500">Baixar arquivo .JSON</p>
                    </div>
                 </button>

                 <div className="relative">
                    <input 
                      type="file" 
                      accept=".json" 
                      className="hidden" 
                      ref={fileInputRef} 
                      onChange={handleImportRestore} 
                    />
                    <button 
                        onClick={() => fileInputRef.current?.click()}
                        disabled={restoring}
                        className="w-full flex items-center gap-3 p-4 bg-slate-50 hover:bg-slate-100 border border-slate-200 rounded-xl transition-all group disabled:opacity-50"
                    >
                        <div className="p-2 bg-white rounded-lg text-emerald-600 shadow-sm group-hover:scale-110 transition-transform">
                          {restoring ? <Loader2 className="animate-spin" size={20} /> : <Upload size={20} />}
                        </div>
                        <div className="text-left">
                          <p className="font-bold text-slate-800 text-sm">Restaurar Dados</p>
                          <p className="text-[10px] text-slate-500">Upload de arquivo .JSON</p>
                        </div>
                    </button>
                 </div>

                 <button 
                    onClick={handleManualSync}
                    disabled={syncing}
                    className="flex items-center gap-3 p-4 bg-slate-50 hover:bg-slate-100 border border-slate-200 rounded-xl transition-all group md:col-span-2 disabled:opacity-50"
                 >
                    <div className={`p-2 bg-white rounded-lg text-blue-900 shadow-sm ${syncing ? 'animate-spin' : 'group-hover:rotate-180'} transition-all duration-500`}>
                       <RefreshCw size={20} />
                    </div>
                    <div className="text-left">
                       <p className="font-bold text-slate-800 text-sm">Sincronizar com Banco</p>
                       <p className="text-[10px] text-slate-500">Atualizar dados com o servidor Supabase</p>
                    </div>
                 </button>
              </div>
           </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-blue-50 lg:col-span-2">
           <div className="flex items-center gap-3 mb-6">
              <div className="p-2 bg-blue-100 text-blue-600 rounded-lg">
                <Tag size={20} />
              </div>
              <h3 className="font-bold text-blue-900 text-lg">Gerenciar Categorias</h3>
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div>
                    <p className="text-xs font-bold text-blue-600 uppercase mb-3">Entradas</p>
                    <div className="space-y-2">
                        {categories.filter(c => c.type === 'income').map(cat => (
                            <div key={cat.id} className="flex items-center justify-between p-3 bg-slate-50 rounded-xl group border border-blue-50">
                                {editingCatId === cat.id ? (
                                    <input 
                                        type="text" 
                                        className="flex-1 bg-white text-sm p-1 border border-blue-200 rounded outline-none"
                                        value={catTempName}
                                        onChange={e => setCatTempName(e.target.value)}
                                        autoFocus
                                    />
                                ) : (
                                    <span className="text-sm font-medium text-slate-700">{cat.name}</span>
                                )}
                                <div className="flex gap-2">
                                    {editingCatId === cat.id ? (
                                        <>
                                            <button onClick={handleSaveCat} className="text-blue-600 hover:bg-blue-50 p-1 rounded"><Check size={16}/></button>
                                            <button onClick={() => setEditingCatId(null)} className="text-slate-400 p-1 rounded"><X size={16}/></button>
                                        </>
                                    ) : (
                                        <>
                                            <button onClick={() => handleStartEditCat(cat)} className="text-slate-400 hover:text-blue-600 p-1 opacity-0 group-hover:opacity-100 transition-opacity"><Pencil size={16}/></button>
                                            <button onClick={() => {if(confirm('Excluir categoria?')) deleteCategory(cat.id)}} className="text-slate-400 hover:text-red-600 p-1 opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 size={16}/></button>
                                        </>
                                    )}
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
                <div>
                    <p className="text-xs font-bold text-red-600 uppercase mb-3">Saídas</p>
                    <div className="space-y-2">
                        {categories.filter(c => c.type === 'expense').map(cat => (
                            <div key={cat.id} className="flex items-center justify-between p-3 bg-slate-50 rounded-xl group border border-blue-50">
                                {editingCatId === cat.id ? (
                                    <input 
                                        type="text" 
                                        className="flex-1 bg-white text-sm p-1 border border-blue-200 rounded outline-none"
                                        value={catTempName}
                                        onChange={e => setCatTempName(e.target.value)}
                                        autoFocus
                                    />
                                ) : (
                                    <span className="text-sm font-medium text-slate-700">{cat.name}</span>
                                )}
                                <div className="flex gap-2">
                                    {editingCatId === cat.id ? (
                                        <>
                                            <button onClick={handleSaveCat} className="text-blue-600 hover:bg-blue-50 p-1 rounded"><Check size={16}/></button>
                                            <button onClick={() => setEditingCatId(null)} className="text-slate-400 p-1 rounded"><X size={16}/></button>
                                        </>
                                    ) : (
                                        <>
                                            <button onClick={() => handleStartEditCat(cat)} className="text-slate-400 hover:text-blue-600 p-1 opacity-0 group-hover:opacity-100 transition-opacity"><Pencil size={16}/></button>
                                            <button onClick={() => {if(confirm('Excluir categoria?')) deleteCategory(cat.id)}} className="text-slate-400 hover:text-red-600 p-1 opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 size={16}/></button>
                                        </>
                                    )}
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
           </div>
        </div>
      </div>
    </div>
  );
};

export default Settings;

export type TransactionType = 'income' | 'expense';
export type TransactionStatus = 'pending' | 'completed' | 'cancelled';
export type PaymentMethod = 'bank_transfer' | 'credit_card' | 'cash' | 'check' | 'pix';
export type ProjectStatus = 'planned' | 'ongoing' | 'completed' | 'cancelled';
export type OfficialDocType = 'oficio' | 'comissao' | 'escala';

export interface Category {
  id: string;
  name: string;
  type: TransactionType;
  budgetLimit?: number;
}

export interface Account {
  id: string;
  name: string;
  type: 'bank' | 'cash' | 'savings';
  description?: string;
  initialBalance: number;
}

export interface Transaction {
  id: string;
  date: string;
  description: string;
  amount: number;
  type: TransactionType;
  category: string;
  accountId: string;
  status: TransactionStatus;
  paymentMethod: PaymentMethod;
  notes?: string;
  attachment?: string;
  reconciled: boolean;
}

export interface BoardMember {
  id: string;
  name: string;
  role: string;
  termStart: string;
  termEnd: string;
  phone?: string;
  email?: string;
}

export interface Project {
  id: string;
  title: string;
  description: string;
  objective: string;
  targetAudience: string;
  resources: string;
  financialImpact: number;
  executionDate: string;
  executionLocation: string;
  status: ProjectStatus;
  authorId?: string;
}

export interface OfficialDocument {
  id: string;
  type: OfficialDocType;
  title: string;
  content: any;
  created_at: string;
}

export interface FinancialSummary {
  totalIncome: number;
  totalExpense: number;
  balance: number;
  pendingIncome: number;
  pendingExpense: number;
}

export interface AIAnalysisResult {
  summary: string;
  risks: string[];
  recommendations: string[];
  lastUpdated: string;
}

import React, { createContext, useContext, useState, ReactNode, useEffect } from 'react';
import { Transaction, Category, FinancialSummary, Account, BoardMember, Project, OfficialDocument } from '../types';
import { supabase } from '../services/supabaseClient';

interface DocumentMetadata {
  id: string;
  name: string;
  file_url: string;
  folder: string;
  created_at: string;
}

interface FinanceContextType {
  transactions: Transaction[];
  categories: Category[];
  accounts: Account[];
  documents: DocumentMetadata[];
  boardMembers: BoardMember[];
  projects: Project[];
  officialDocuments: OfficialDocument[];
  associationName: string;
  loading: boolean;
  updateAssociationName: (name: string) => Promise<void>;
  addTransaction: (t: Omit<Transaction, 'id'>) => Promise<void>;
  updateTransaction: (t: Transaction) => Promise<void>;
  deleteTransaction: (id: string) => Promise<void>;
  addAccount: (a: Omit<Account, 'id'>) => Promise<void>;
  updateAccount: (a: Account) => Promise<void>;
  deleteAccount: (id: string) => Promise<void>;
  addCategory: (c: Omit<Category, 'id'>) => Promise<void>;
  updateCategory: (id: string, name: string) => Promise<void>;
  deleteCategory: (id: string) => Promise<void>;
  addDocument: (name: string, url: string, folder: string) => Promise<void>;
  addBoardMember: (m: Omit<BoardMember, 'id'>) => Promise<void>;
  deleteBoardMember: (id: string) => Promise<void>;
  addProject: (p: Omit<Project, 'id'>) => Promise<void>;
  updateProject: (p: Project) => Promise<void>;
  deleteProject: (id: string) => Promise<void>;
  addOfficialDocument: (d: Omit<OfficialDocument, 'id' | 'created_at'>) => Promise<void>;
  deleteOfficialDocument: (id: string) => Promise<void>;
  fetchInitialData: () => Promise<void>;
  getSummary: () => FinancialSummary;
}

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const FinanceProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [accounts, setAccounts] = useState<Account[]>([]);
  const [documents, setDocuments] = useState<DocumentMetadata[]>([]);
  const [boardMembers, setBoardMembers] = useState<BoardMember[]>([]);
  const [projects, setProjects] = useState<Project[]>([]);
  const [officialDocuments, setOfficialDocuments] = useState<OfficialDocument[]>([]);
  const [associationName, setAssociationName] = useState('Associação Integrada');
  const [loading, setLoading] = useState(true);

  const mapAccount = (dbAcc: any): Account => ({
    id: dbAcc.id,
    name: dbAcc.name,
    type: dbAcc.type,
    description: dbAcc.description,
    initialBalance: Number(dbAcc.initial_balance)
  });

  const mapTransaction = (dbTrans: any): Transaction => ({
    id: dbTrans.id,
    date: dbTrans.date,
    description: dbTrans.description,
    amount: Number(dbTrans.amount),
    type: dbTrans.type,
    category: dbTrans.category,
    accountId: dbTrans.account_id,
    status: dbTrans.status,
    paymentMethod: dbTrans.payment_method,
    notes: dbTrans.notes,
    attachment: dbTrans.attachment,
    reconciled: dbTrans.reconciled || false
  });

  const mapBoardMember = (db: any): BoardMember => ({
    id: db.id,
    name: db.name,
    role: db.role,
    termStart: db.term_start,
    termEnd: db.term_end,
    phone: db.phone,
    email: db.email
  });

  const mapProject = (db: any): Project => ({
    id: db.id,
    title: db.title,
    description: db.description,
    objective: db.objective || '',
    targetAudience: db.target_audience || '',
    resources: db.resources || '',
    financialImpact: Number(db.financial_impact || 0),
    executionDate: db.execution_date || db.start_date || '',
    executionLocation: db.execution_location || '',
    status: db.status,
    authorId: db.author_id
  });

  const fetchInitialData = async () => {
    setLoading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;

      const [p, acc, cat, trans, docs, board, projs, offDocs] = await Promise.all([
        supabase.from('profiles').select('*').eq('id', user.id).single(),
        supabase.from('accounts').select('*').eq('user_id', user.id),
        supabase.from('categories').select('*').eq('user_id', user.id),
        supabase.from('transactions').select('*').eq('user_id', user.id).order('date', { ascending: false }),
        supabase.from('documents').select('*').eq('user_id', user.id).order('created_at', { ascending: false }),
        supabase.from('board_members').select('*').eq('user_id', user.id),
        supabase.from('projects').select('*').eq('user_id', user.id).order('created_at', { ascending: false }),
        supabase.from('official_documents').select('*').eq('user_id', user.id).order('created_at', { ascending: false })
      ]);

      if (p.data) setAssociationName(p.data.association_name);
      if (acc.data) setAccounts(acc.data.map(mapAccount));
      if (cat.data) setCategories(cat.data);
      if (trans.data) setTransactions(trans.data.map(mapTransaction));
      if (docs.data) setDocuments(docs.data);
      if (board.data) setBoardMembers(board.data.map(mapBoardMember));
      if (projs.data) setProjects(projs.data.map(mapProject));
      if (offDocs.data) setOfficialDocuments(offDocs.data);
    } catch (error) {
      console.error('Erro ao carregar dados:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchInitialData();
  }, []);

  const updateAssociationName = async (name: string) => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;
    const { error } = await supabase.from('profiles').upsert({ id: user.id, association_name: name });
    if (!error) setAssociationName(name);
  };

  const addTransaction = async (t: Omit<Transaction, 'id'>) => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;
    const dbPayload = {
      user_id: user.id, date: t.date, description: t.description, amount: t.amount, type: t.type,
      category: t.category, account_id: t.accountId, status: t.status, payment_method: t.paymentMethod,
      notes: t.notes, attachment: t.attachment, reconciled: t.reconciled
    };
    const { data, error } = await supabase.from('transactions').insert([dbPayload]).select().single();
    if (data) setTransactions(prev => [mapTransaction(data), ...prev]);
  };

  const updateTransaction = async (updated: Transaction) => {
    const dbPayload = {
      date: updated.date, description: updated.description, amount: updated.amount, type: updated.type,
      category: updated.category, account_id: updated.accountId, status: updated.status,
      payment_method: updated.paymentMethod, notes: updated.notes, attachment: updated.attachment, reconciled: updated.reconciled
    };
    await supabase.from('transactions').update(dbPayload).eq('id', updated.id);
    setTransactions(prev => prev.map(t => t.id === updated.id ? updated : t));
  };

  const deleteTransaction = async (id: string) => {
    await supabase.from('transactions').delete().eq('id', id);
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const addAccount = async (a: Omit<Account, 'id'>) => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;
    const dbPayload = { user_id: user.id, name: a.name, type: a.type, initial_balance: a.initialBalance, description: a.description };
    const { data } = await supabase.from('accounts').insert([dbPayload]).select().single();
    if (data) setAccounts(prev => [...prev, mapAccount(data)]);
  };

  const updateAccount = async (updated: Account) => {
    const dbPayload = { name: updated.name, type: updated.type, initial_balance: updated.initialBalance, description: updated.description };
    await supabase.from('accounts').update(dbPayload).eq('id', updated.id);
    setAccounts(prev => prev.map(a => a.id === updated.id ? updated : a));
  };

  const deleteAccount = async (id: string) => {
    await supabase.from('accounts').delete().eq('id', id);
    setAccounts(prev => prev.filter(a => a.id !== id));
  };

  const addCategory = async (c: Omit<Category, 'id'>) => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;
    const { data } = await supabase.from('categories').insert([{ ...c, user_id: user.id }]).select().single();
    if (data) setCategories(prev => [...prev, data]);
  };

  const updateCategory = async (id: string, name: string) => {
    await supabase.from('categories').update({ name }).eq('id', id);
    setCategories(prev => prev.map(c => c.id === id ? { ...c, name } : c));
  };

  const deleteCategory = async (id: string) => {
    await supabase.from('categories').delete().eq('id', id);
    setCategories(prev => prev.filter(c => c.id !== id));
  };

  const addDocument = async (name: string, url: string, folder: string) => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;
    const { data } = await supabase.from('documents').insert([{ name, file_url: url, folder, user_id: user.id }]).select().single();
    if (data) setDocuments(prev => [data, ...prev]);
  };

  const addBoardMember = async (m: Omit<BoardMember, 'id'>) => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) throw new Error("Usuário não autenticado");

    const dbPayload = { 
      user_id: user.id, 
      name: m.name, 
      role: m.role, 
      term_start: m.termStart, 
      term_end: m.termEnd, 
      phone: m.phone || null, 
      email: m.email || null 
    };

    const { data, error } = await supabase.from('board_members').insert([dbPayload]).select().single();
    if (error) throw error;
    if (data) setBoardMembers(prev => [...prev, mapBoardMember(data)]);
  };

  const deleteBoardMember = async (id: string) => {
    const { error } = await supabase.from('board_members').delete().eq('id', id);
    if (error) throw error;
    setBoardMembers(prev => prev.filter(m => m.id !== id));
  };

  const addProject = async (p: Omit<Project, 'id'>) => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) throw new Error("Usuário não autenticado");

    const dbPayload = { 
      user_id: user.id, 
      title: p.title, 
      description: p.description, 
      objective: p.objective,
      target_audience: p.targetAudience,
      resources: p.resources,
      financial_impact: p.financialImpact,
      execution_date: p.executionDate,
      execution_location: p.executionLocation,
      status: p.status,
      author_id: p.authorId || null -- AGORA REATIVADO
    };

    const { data, error } = await supabase.from('projects').insert([dbPayload]).select().single();
    if (error) throw error;
    if (data) setProjects(prev => [mapProject(data), ...prev]);
  };

  const updateProject = async (p: Project) => {
    const dbPayload = { 
      title: p.title, 
      description: p.description, 
      objective: p.objective,
      target_audience: p.targetAudience,
      resources: p.resources,
      financial_impact: p.financialImpact,
      execution_date: p.executionDate,
      execution_location: p.executionLocation,
      status: p.status,
      author_id: p.authorId || null
    };
    const { error } = await supabase.from('projects').update(dbPayload).eq('id', p.id);
    if (error) throw error;
    setProjects(prev => prev.map(proj => proj.id === p.id ? p : proj));
  };

  const deleteProject = async (id: string) => {
    const { error } = await supabase.from('projects').delete().eq('id', id);
    if (error) throw error;
    setProjects(prev => prev.filter(p => p.id !== id));
  };

  const addOfficialDocument = async (d: Omit<OfficialDocument, 'id' | 'created_at'>) => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;
    const { data } = await supabase.from('official_documents').insert([{ ...d, user_id: user.id }]).select().single();
    if (data) setOfficialDocuments(prev => [data, ...prev]);
  };

  const deleteOfficialDocument = async (id: string) => {
    await supabase.from('official_documents').delete().eq('id', id);
    setOfficialDocuments(prev => prev.filter(d => d.id !== id));
  };

  const getSummary = (): FinancialSummary => {
    return transactions.reduce((acc, t) => {
      const isIncome = t.type === 'income';
      const isCompleted = t.status === 'completed';
      if (isIncome) {
        if (isCompleted) acc.totalIncome += t.amount;
        else acc.pendingIncome += t.amount;
      } else {
        if (isCompleted) acc.totalExpense += t.amount;
        else acc.pendingExpense += t.amount;
      }
      if (isCompleted) acc.balance += isIncome ? t.amount : -t.amount;
      return acc;
    }, { totalIncome: 0, totalExpense: 0, balance: 0, pendingIncome: 0, pendingExpense: 0 });
  };

  return (
    <FinanceContext.Provider value={{
      transactions, categories, accounts, documents, boardMembers, projects, officialDocuments, associationName, loading,
      updateAssociationName, addTransaction, updateTransaction, deleteTransaction,
      addAccount, updateAccount, deleteAccount, addCategory, updateCategory, deleteCategory,
      addDocument, addBoardMember, deleteBoardMember, addProject, updateProject, deleteProject,
      addOfficialDocument, deleteOfficialDocument, fetchInitialData, getSummary
    }}>
      {children}
    </FinanceContext.Provider>
  );
};

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error('useFinance deve ser usado dentro de um FinanceProvider');
  return context;
};

